(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,683565,n=>{"use strict";n.s(["ALL_DIALOGUES_KO",0,[{id:"ko-dlg-a1-greetings-001",level:"A1",situation:"greetings",context:{ko:"처음 만난 사람과 인사",en:"Greeting someone you just met",zh:"初次见面时打招呼",vi:"Chào hỏi người mới gặp lần đầu"},prompt:{ko:"안녕하세요! 만나서 반갑습니다.",en:"Hello! Nice to meet you.",zh:"你好！很高兴认识你。",vi:"Xin chào! Rất vui được gặp bạn."},template:"안녕하세요, 저도 {0}.",blanks:[[{ko:"반갑습니다",en:"glad to meet you (polite)",zh:"很高兴认识你",vi:"rất vui được gặp (lịch sự)",note:"Standard polite register.",noteZh:"标准礼貌语体。",noteVi:"Cách nói lịch sự tiêu chuẩn."},{ko:"반가워요",en:"glad to meet you (softer)",zh:"很高兴认识你（更柔和）",vi:"rất vui được gặp (nhẹ nhàng hơn)",note:"A little softer, still polite.",noteZh:"语气更柔和，但仍然礼貌。",noteVi:"Nhẹ nhàng hơn một chút, nhưng vẫn lịch sự."}]],example:{ko:"안녕하세요, 저도 반갑습니다.",en:"Hello, I'm glad to meet you too.",zh:"你好，我也很高兴认识你。",vi:"Xin chào, tôi cũng rất vui được gặp bạn."},alternatives:[{ko:"처음 뵙겠습니다.",en:"How do you do? (first meeting)",zh:"初次见面，请多关照。",vi:"Rất hân hạnh được gặp bạn lần đầu.",note:"Very formal first-meeting greeting.",noteZh:"非常正式的初次见面问候语。",noteVi:"Lời chào rất trang trọng khi gặp mặt lần đầu."},{ko:"말씀 많이 들었어요.",en:"I've heard a lot about you.",zh:"久仰大名。",vi:"Tôi đã nghe nói nhiều về bạn.",note:"Friendly, when you already know of them.",noteZh:"当你已经听说过对方时，用来表示友好。",noteVi:"Thân thiện, dùng khi bạn đã biết về người đó từ trước."}]},{id:"ko-dlg-a1-greetings-002",level:"A1",situation:"greetings",context:{ko:"도움을 받았을 때",en:"When someone helps you",zh:"得到帮助时",vi:"Khi được ai đó giúp đỡ"},prompt:{ko:"여기 있습니다. 도와드릴게요.",en:"Here you go. Let me help you.",zh:"给您。我来帮您。",vi:"Đây ạ. Để tôi giúp bạn."},template:"{0}, 정말 {1}.",blanks:[[{ko:"감사합니다",en:"thank you (formal)",zh:"谢谢（正式）",vi:"cảm ơn (trang trọng)",note:"Formal, safe everywhere.",noteZh:"正式用语，任何场合都适用。",noteVi:"Trang trọng, dùng an toàn ở mọi nơi."},{ko:"고맙습니다",en:"thank you (warm)",zh:"谢谢（亲切）",vi:"cảm ơn (ấm áp)",note:"Warm and natural.",noteZh:"亲切自然。",noteVi:"Ấm áp và tự nhiên."}],[{ko:"감사해요",en:"I appreciate it",zh:"我很感激",vi:"tôi rất cảm kích",note:"Polite, conversational.",noteZh:"礼貌，口语化。",noteVi:"Lịch sự, mang tính hội thoại."},{ko:"고마워요",en:"thanks",zh:"谢谢",vi:"cảm ơn nhé",note:"Casual-polite.",noteZh:"随和又礼貌。",noteVi:"Thân mật nhưng lịch sự."}]],example:{ko:"감사합니다, 정말 감사해요.",en:"Thank you, I really appreciate it.",zh:"谢谢，真的很感激。",vi:"Cảm ơn, tôi thật sự rất cảm kích."},alternatives:[{ko:"덕분이에요.",en:"It's thanks to you.",zh:"多亏了您。",vi:"Nhờ có bạn cả đấy.",note:"Gives the other person credit.",noteZh:"把功劳归于对方。",noteVi:"Ghi nhận công lao của đối phương."}]},{id:"ko-dlg-a1-self-intro-001",level:"A1",situation:"self-intro",context:{ko:"이름을 물어볼 때",en:"When someone asks your name",zh:"被问到姓名时",vi:"Khi ai đó hỏi tên bạn"},prompt:{ko:"안녕하세요, 이름이 뭐예요?",en:"Hello, what's your name?",zh:"你好，你叫什么名字？",vi:"Xin chào, bạn tên là gì?"},template:"안녕하세요, 저는 {0}.",blanks:[[{ko:"사라예요",en:"Sarah (after a vowel)",zh:"是莎拉（元音结尾）",vi:"là Sarah (sau nguyên âm)",note:"Use 예요 when the name ends in a vowel.",noteZh:"名字以元音结尾时用예요。",noteVi:"Dùng 예요 khi tên kết thúc bằng nguyên âm."},{ko:"민준이에요",en:"Minjun (after a consonant)",zh:"是民俊（辅音结尾）",vi:"là Minjun (sau phụ âm)",note:"Use 이에요 when the name ends in a consonant.",noteZh:"名字以辅音结尾时用이에요。",noteVi:"Dùng 이에요 khi tên kết thúc bằng phụ âm."}]],example:{ko:"안녕하세요, 저는 사라예요.",en:"Hello, I'm Sarah.",zh:"你好，我是莎拉。",vi:"Xin chào, tôi là Sarah."},alternatives:[{ko:"제 이름은 사라예요.",en:"My name is Sarah.",zh:"我的名字是莎拉。",vi:"Tên tôi là Sarah.",note:"More explicit, names yourself directly.",noteZh:"更明确，直接说出自己的名字。",noteVi:"Rõ ràng hơn, nói thẳng tên của mình."},{ko:"사라라고 해요.",en:"I'm called Sarah.",zh:"我叫莎拉。",vi:"Tôi tên là Sarah.",note:"Slightly more formal self-introduction.",noteZh:"稍微更正式的自我介绍方式。",noteVi:"Cách tự giới thiệu trang trọng hơn một chút."}]},{id:"ko-dlg-a1-numbers-001",level:"A1",situation:"numbers",context:{ko:"가게에서 가격을 물어볼 때",en:"Asking a price at a shop",zh:"在商店询问价格时",vi:"Khi hỏi giá ở cửa hàng"},prompt:{ko:"어서 오세요! 뭐 드릴까요?",en:"Welcome! What can I get you?",zh:"欢迎光临！您需要点什么？",vi:"Xin chào quý khách! Quý khách cần gì ạ?"},template:"이거 {0} 주세요. 얼마예요?",blanks:[[{ko:"한 개",en:"one (item)",zh:"一个",vi:"một cái",note:"하나 becomes 한 before the counter 개.",noteZh:"하나在量词개前变成한。",noteVi:"하나 biến thành 한 khi đứng trước lượng từ 개."},{ko:"두 개",en:"two (items)",zh:"两个",vi:"hai cái",note:"둘 becomes 두 before the counter 개.",noteZh:"둘在量词개前变成두。",noteVi:"둘 biến thành 두 khi đứng trước lượng từ 개."},{ko:"세 개",en:"three (items)",zh:"三个",vi:"ba cái",note:"셋 becomes 세 before the counter 개.",noteZh:"셋在量词개前变成세。",noteVi:"셋 biến thành 세 khi đứng trước lượng từ 개."}]],example:{ko:"이거 한 개 주세요. 얼마예요?",en:"I'll have one of these. How much is it?",zh:"请给我一个这个。多少钱？",vi:"Cho tôi một cái này. Bao nhiêu tiền ạ?"},alternatives:[{ko:"모두 얼마예요?",en:"How much is it all together?",zh:"一共多少钱？",vi:"Tất cả bao nhiêu tiền?",note:"Asks for the total.",noteZh:"询问总金额。",noteVi:"Hỏi tổng số tiền."},{ko:"카드 돼요?",en:"Can I pay by card?",zh:"可以刷卡吗？",vi:"Có thể trả bằng thẻ không?",note:"Handy when paying.",noteZh:"付款时很实用的说法。",noteVi:"Hữu ích khi thanh toán."}]},{id:"ko-dlg-a1-food-001",level:"A1",situation:"food",context:{ko:"식당에서 주문할 때",en:"Ordering at a restaurant",zh:"在餐厅点餐时",vi:"Khi gọi món ở nhà hàng"},prompt:{ko:"주문하시겠어요?",en:"Are you ready to order?",zh:"您要点餐了吗？",vi:"Quý khách muốn gọi món chưa ạ?"},template:"네, {0} 주세요.",blanks:[[{ko:"비빔밥",en:"bibimbap",zh:"拌饭",vi:"cơm trộn bibimbap",note:"A popular rice dish — a safe first order.",noteZh:"很受欢迎的拌饭料理，第一次点餐的稳妥之选。",noteVi:"Món cơm nổi tiếng — lựa chọn an toàn cho lần gọi món đầu tiên."},{ko:"불고기",en:"bulgogi (marinated beef)",zh:"烤牛肉（韩式烤肉）",vi:"thịt bò nướng bulgogi",note:"Sweet grilled beef, usually not spicy.",noteZh:"略带甜味的烤牛肉，通常不辣。",noteVi:"Thịt bò nướng ướp ngọt, thường không cay."},{ko:"냉면",en:"naengmyeon (cold noodles)",zh:"冷面",vi:"mì lạnh naengmyeon",note:"Chilled buckwheat noodles, great in summer.",noteZh:"冰镇荞麦面，夏天吃很棒。",noteVi:"Mì kiều mạch lạnh, rất tuyệt vào mùa hè."}]],example:{ko:"네, 비빔밥 주세요.",en:"Yes, I'll have bibimbap.",zh:"好的，请给我拌饭。",vi:"Vâng, cho tôi cơm trộn bibimbap."},alternatives:[{ko:"이거 매워요?",en:"Is this spicy?",zh:"这个辣吗？",vi:"Món này có cay không?",note:"Useful if you want to check the spice level.",noteZh:"想确认辣度时很有用。",noteVi:"Hữu ích khi bạn muốn kiểm tra độ cay."},{ko:"물 좀 주세요.",en:"Some water, please.",zh:"请给我一点水。",vi:"Cho tôi xin chút nước.",note:"Politely ask for water with 좀.",noteZh:"用좀礼貌地要水。",noteVi:"Dùng 좀 để yêu cầu nước một cách lịch sự."}]},{id:"ko-dlg-a1-family-001",level:"A1",situation:"family",context:{ko:"가족에 대해 이야기할 때",en:"Talking about your family",zh:"谈论家人时",vi:"Khi nói về gia đình của bạn"},prompt:{ko:"가족이 몇 명이에요?",en:"How many people are in your family?",zh:"您家有几口人？",vi:"Gia đình bạn có mấy người?"},template:"{0}이에요. {1} 있어요.",blanks:[[{ko:"세 명",en:"three people",zh:"三个人",vi:"ba người",note:"Native number 세 + counter 명 (people).",noteZh:"固有数词세＋量词명（人）。",noteVi:"Số đếm thuần Hàn 세 + lượng từ 명 (người)."},{ko:"네 명",en:"four people",zh:"四个人",vi:"bốn người",note:"Native number 네 + counter 명 (people).",noteZh:"固有数词네＋量词명（人）。",noteVi:"Số đếm thuần Hàn 네 + lượng từ 명 (người)."}],[{ko:"동생이 한 명",en:"one younger sibling",zh:"一个弟弟（或妹妹）",vi:"một em (trai/gái)",note:"동생 works for a younger brother or sister.",noteZh:"동생可指弟弟或妹妹。",noteVi:"동생 dùng cho cả em trai lẫn em gái."},{ko:"형이 한 명",en:"one older brother (male speaker)",zh:"一个哥哥（男性说话者）",vi:"một anh trai (người nói là nam)",note:"A male speaker says 형 for an older brother.",noteZh:"男性称呼哥哥用형。",noteVi:"Người nói là nam giới gọi anh trai là 형."},{ko:"언니가 한 명",en:"one older sister (female speaker)",zh:"一个姐姐（女性说话者）",vi:"một chị gái (người nói là nữ)",note:"A female speaker says 언니 for an older sister.",noteZh:"女性称呼姐姐用언니。",noteVi:"Người nói là nữ giới gọi chị gái là 언니."}]],example:{ko:"네 명이에요. 동생이 한 명 있어요.",en:"There are four of us. I have one younger sibling.",zh:"是四个人。我有一个弟弟（或妹妹）。",vi:"Là bốn người. Tôi có một đứa em."},alternatives:[{ko:"형제가 없어요.",en:"I don't have any siblings.",zh:"我没有兄弟姐妹。",vi:"Tôi không có anh chị em.",note:"Use 없어요 to say you have none.",noteZh:"用없어요表示什么都没有。",noteVi:"Dùng 없어요 để nói rằng không có gì cả."},{ko:"부모님과 같이 살아요.",en:"I live with my parents.",zh:"我和父母一起住。",vi:"Tôi sống cùng bố mẹ.",note:"부모님 = parents (honorific).",noteZh:"부모님即父母（敬语）。",noteVi:"부모님 nghĩa là bố mẹ (dạng kính ngữ)."}]},{id:"ko-dlg-a2-shopping-001",level:"A2",situation:"shopping",context:{ko:"가게에서 가격을 물어볼 때",en:"Asking the price in a store",zh:"在店里询问价格时",vi:"Khi hỏi giá ở cửa hàng"},prompt:{ko:"어서 오세요. 찾으시는 거 있으세요?",en:"Welcome. Are you looking for something?",zh:"欢迎光临。您在找什么吗？",vi:"Xin chào quý khách. Quý khách đang tìm gì không?"},template:"이거 {0}? 그리고 {1}.",blanks:[[{ko:"얼마예요",en:"how much is it",zh:"多少钱",vi:"bao nhiêu tiền",note:"The core question for any price.",noteZh:"问价格最核心的问句。",noteVi:"Câu hỏi cốt lõi cho bất kỳ mức giá nào."},{ko:"세일해요",en:"is this on sale",zh:"在打折吗",vi:"có đang giảm giá không",note:"Ask if there's a discount.",noteZh:"询问是否有折扣。",noteVi:"Hỏi xem có được giảm giá không."}],[{ko:"한번 볼게요",en:"I'll take a look",zh:"我看一下",vi:"tôi xem thử đã",note:"Polite, no pressure to buy.",noteZh:"礼貌，不急着买。",noteVi:"Lịch sự, không tạo áp lực phải mua."},{ko:"조금 비싸네요",en:"it's a little pricey",zh:"有点贵呢",vi:"hơi đắt nhỉ",note:"-네요 softly reacts to what you notice.",noteZh:"-네요用于对察觉到的事委婉表态。",noteVi:"-네요 dùng để phản ứng nhẹ nhàng với điều bạn nhận ra."}]],example:{ko:"이거 얼마예요? 그리고 한번 볼게요.",en:"How much is this? And I'll take a look.",zh:"这个多少钱？我先看一下。",vi:"Cái này bao nhiêu tiền? Và tôi xem thử đã."},alternatives:[{ko:"그냥 구경하는 거예요.",en:"I'm just looking.",zh:"我只是看看。",vi:"Tôi chỉ xem thôi.",note:"Friendly way to decline help.",noteZh:"婉拒帮忙的友好说法。",noteVi:"Cách thân thiện để từ chối sự giúp đỡ."},{ko:"다른 색깔도 있어요?",en:"Do you have other colors?",zh:"还有别的颜色吗？",vi:"Có màu khác không?",note:"색깔 = color.",noteZh:"색깔即颜色。",noteVi:"색깔 = màu sắc."}]},{id:"ko-dlg-a2-shopping-002",level:"A2",situation:"shopping",context:{ko:"계산할 때",en:"When paying at the counter",zh:"结账时",vi:"Khi thanh toán"},prompt:{ko:"모두 이만 오천 원입니다. 어떻게 결제하시겠어요?",en:"It's 25,000 won total. How would you like to pay?",zh:"一共两万五千韩元。您想怎么付款？",vi:"Tổng cộng là 25.000 won. Quý khách muốn thanh toán như thế nào?"},template:"{0}. 영수증도 {1}.",blanks:[[{ko:"카드로 할게요",en:"I'll pay by card",zh:"我刷卡",vi:"tôi trả bằng thẻ",note:"(으)로 marks the payment method.",noteZh:"(으)로表示付款方式。",noteVi:"(으)로 đánh dấu phương thức thanh toán."},{ko:"현금으로 낼게요",en:"I'll pay in cash",zh:"我付现金",vi:"tôi trả bằng tiền mặt",note:"현금 = cash; 내다 = to pay.",noteZh:"현금即现金；내다即支付。",noteVi:"현금 = tiền mặt; 내다 = trả (tiền)."}],[{ko:"주세요",en:"please give me",zh:"请给我",vi:"cho tôi xin",note:"Standard polite request.",noteZh:"标准的礼貌请求。",noteVi:"Cách yêu cầu lịch sự thông thường."},{ko:"받을게요",en:"I'll take it",zh:"我要",vi:"tôi sẽ nhận",note:"Stating you'll accept it.",noteZh:"表示你会收下。",noteVi:"Thể hiện rằng bạn sẽ nhận lấy nó."}]],example:{ko:"카드로 할게요. 영수증도 주세요.",en:"I'll pay by card. Please give me a receipt too.",zh:"我刷卡。也请给我收据。",vi:"Tôi trả bằng thẻ. Cho tôi xin cả hóa đơn nữa."},alternatives:[{ko:"봉투 하나 주세요.",en:"Please give me a bag.",zh:"请给我一个袋子。",vi:"Cho tôi xin một cái túi.",note:"봉투 = bag; often costs extra in Korea.",noteZh:"봉투即袋子；在韩国常需另外付费。",noteVi:"봉투 = túi; ở Hàn Quốc thường phải trả thêm tiền."},{ko:"할인 되나요?",en:"Is there a discount?",zh:"能打折吗？",vi:"Có được giảm giá không?",note:"되나요? = is it possible?",noteZh:"되나요?意为“可以吗？”。",noteVi:"되나요? nghĩa là 'có được không?'."}]},{id:"ko-dlg-a2-transport-001",level:"A2",situation:"transport",context:{ko:"길을 물어볼 때",en:"Asking for directions",zh:"问路时",vi:"Khi hỏi đường"},prompt:{ko:"어디 찾으세요? 도와드릴까요?",en:"What are you looking for? Can I help you?",zh:"您找哪里？需要帮忙吗？",vi:"Anh/chị tìm gì vậy? Tôi giúp được không?"},template:"네, {0}? {1}.",blanks:[[{ko:"지하철역이 어디예요",en:"where is the subway station",zh:"地铁站在哪里",vi:"ga tàu điện ngầm ở đâu",note:"역 = station.",noteZh:"역即站。",noteVi:"역 = ga."},{ko:"버스 정류장이 어디예요",en:"where is the bus stop",zh:"公交车站在哪里",vi:"trạm xe buýt ở đâu",note:"정류장 = stop.",noteZh:"정류장即车站。",noteVi:"정류장 = trạm dừng."}],[{ko:"여기서 멀어요",en:"is it far from here",zh:"离这里远吗",vi:"có xa đây không",note:"멀다 = far.",noteZh:"멀다即远。",noteVi:"멀다 = xa."},{ko:"걸어갈 수 있어요",en:"can I walk there",zh:"可以走过去吗",vi:"có thể đi bộ đến đó không",note:"걸어가다 = to go on foot.",noteZh:"걸어가다即步行前往。",noteVi:"걸어가다 = đi bộ đến."}]],example:{ko:"네, 지하철역이 어디예요? 여기서 멀어요?",en:"Yes, where is the subway station? Is it far from here?",zh:"是的，地铁站在哪里？离这里远吗？",vi:"Vâng, ga tàu điện ngầm ở đâu ạ? Có xa đây không?"},alternatives:[{ko:"쭉 가면 돼요?",en:"Do I just go straight?",zh:"一直往前走就行吗？",vi:"Cứ đi thẳng là được phải không?",note:"쭉 = straight; -면 돼요? = is it okay if…?",noteZh:"쭉即一直；-면 돼요?意为“……就可以吗？”。",noteVi:"쭉 = thẳng; -면 돼요? nghĩa là '...thì có được không?'."},{ko:"택시를 타는 게 나아요?",en:"Is it better to take a taxi?",zh:"打车会更好吗？",vi:"Đi taxi thì tốt hơn phải không?",note:"-는 게 나아요? = is it better to…?",noteZh:"-는 게 나아요?意为“……会更好吗？”。",noteVi:"-는 게 나아요? nghĩa là '...thì tốt hơn phải không?'."}]},{id:"ko-dlg-a2-transport-002",level:"A2",situation:"transport",context:{ko:"택시 안에서",en:"Inside a taxi",zh:"在出租车里",vi:"Ở trong taxi"},prompt:{ko:"안녕하세요, 어디로 모실까요?",en:"Hello, where would you like to go?",zh:"您好，请问去哪里？",vi:"Xin chào, quý khách muốn đi đâu ạ?"},template:"{0} 가 주세요. {1}.",blanks:[[{ko:"이 주소로",en:"to this address",zh:"去这个地址",vi:"đến địa chỉ này",note:"주소 = address; show it on your phone.",noteZh:"주소即地址；可以用手机给司机看。",noteVi:"주소 = địa chỉ; có thể cho tài xế xem trên điện thoại."},{ko:"서울역으로",en:"to Seoul Station",zh:"去首尔站",vi:"đến ga Seoul",note:"Destination + (으)로 = toward.",noteZh:"目的地＋(으)로意为“往……”。",noteVi:"Điểm đến + (으)로 nghĩa là 'hướng về phía...'."}],[{ko:"좀 빨리 가 주세요",en:"please go a bit quickly",zh:"请快一点",vi:"đi nhanh một chút giúp tôi",note:"빨리 = quickly; polite urgency.",noteZh:"빨리即快；礼貌地表示着急。",noteVi:"빨리 = nhanh; cách thể hiện sự vội vàng một cách lịch sự."},{ko:"천천히 가도 돼요",en:"you can go slowly",zh:"慢慢开也没关系",vi:"đi từ từ cũng được",note:"천천히 = slowly; no rush.",noteZh:"천천히即慢慢地；不着急。",noteVi:"천천히 = từ từ; không cần vội."}]],example:{ko:"이 주소로 가 주세요. 좀 빨리 가 주세요.",en:"Please take me to this address. Please go a bit quickly.",zh:"请带我去这个地址。请开快一点。",vi:"Cho tôi đến địa chỉ này. Đi nhanh một chút giúp tôi."},alternatives:[{ko:"여기서 세워 주세요.",en:"Please stop here.",zh:"请在这里停。",vi:"Dừng lại ở đây giúp tôi.",note:"세우다 = to pull over.",noteZh:"세우다意为“靠边停车”。",noteVi:"세우다 nghĩa là 'tấp xe vào lề'."},{ko:"얼마나 걸려요?",en:"How long will it take?",zh:"要多长时间？",vi:"Mất bao lâu?",note:"걸리다 = to take time.",noteZh:"걸리다意为“花费时间”。",noteVi:"걸리다 nghĩa là 'mất thời gian'."}]},{id:"ko-dlg-a2-time-date-001",level:"A2",situation:"time-date",context:{ko:"약속 시간을 정할 때",en:"Setting a time to meet",zh:"约定见面时间时",vi:"Khi hẹn giờ gặp mặt"},prompt:{ko:"내일 시간 괜찮으세요? 언제 만날까요?",en:"Are you free tomorrow? When shall we meet?",zh:"您明天有空吗？我们什么时候见面？",vi:"Ngày mai anh/chị rảnh không? Khi nào chúng ta gặp nhau?"},template:"{0} 어때요? {1} 봐요.",blanks:[[{ko:"오후 세 시",en:"3 p.m.",zh:"下午三点",vi:"ba giờ chiều",note:"오후 = p.m.; hours use native numbers + 시.",noteZh:"오후即下午；“点”用固有数词加시。",noteVi:"오후 = buổi chiều; giờ dùng số đếm thuần Hàn + 시."},{ko:"점심 시간",en:"lunchtime",zh:"午饭时间",vi:"giờ ăn trưa",note:"점심 = lunch.",noteZh:"점심即午饭。",noteVi:"점심 = bữa trưa."}],[{ko:"카페에서",en:"at the cafe",zh:"在咖啡馆",vi:"ở quán cà phê",note:"에서 marks where an action happens.",noteZh:"에서表示动作发生的地点。",noteVi:"에서 đánh dấu nơi hành động diễn ra."},{ko:"지하철역 앞에서",en:"in front of the subway station",zh:"在地铁站前面",vi:"trước ga tàu điện ngầm",note:"앞 = front.",noteZh:"앞即前面。",noteVi:"앞 = phía trước."}]],example:{ko:"오후 세 시 어때요? 카페에서 봐요.",en:"How about 3 p.m.? Let's meet at the cafe.",zh:"下午三点怎么样？我们在咖啡馆见。",vi:"Ba giờ chiều thế nào? Gặp nhau ở quán cà phê nhé."},alternatives:[{ko:"저는 주말이 더 좋아요.",en:"The weekend is better for me.",zh:"我更喜欢周末。",vi:"Tôi thích cuối tuần hơn.",note:"더 좋아요 = is better.",noteZh:"더 좋아요意为“更好”。",noteVi:"더 좋아요 nghĩa là 'tốt hơn'."},{ko:"조금 늦어도 괜찮아요?",en:"Is it okay if I'm a little late?",zh:"我稍微晚一点可以吗？",vi:"Tôi đến muộn một chút có được không?",note:"-아/어도 괜찮아요? asks permission.",noteZh:"-아/어도 괜찮아요?用来请求许可。",noteVi:"-아/어도 괜찮아요? dùng để xin phép."}]},{id:"ko-dlg-a2-weather-001",level:"A2",situation:"weather",context:{ko:"날씨에 대해 이야기할 때",en:"Chatting about the weather",zh:"聊天气时",vi:"Khi nói chuyện về thời tiết"},prompt:{ko:"오늘 날씨 정말 좋죠? 어디 가세요?",en:"The weather's really nice today, right? Where are you headed?",zh:"今天天气真好，对吧？您去哪里？",vi:"Hôm nay thời tiết đẹp thật nhỉ? Anh/chị đi đâu vậy?"},template:"네, 날씨가 {0}. 그래서 {1}.",blanks:[[{ko:"너무 좋아요",en:"so nice",zh:"非常好",vi:"đẹp lắm",note:"너무 + adjective = really/too.",noteZh:"너무＋形容词意为“非常/太”。",noteVi:"너무 + tính từ nghĩa là 'thật sự/quá'."},{ko:"따뜻해요",en:"warm",zh:"很暖和",vi:"ấm áp",note:"따뜻하다 = pleasantly warm.",noteZh:"따뜻하다指“暖和舒适”。",noteVi:"따뜻하다 chỉ 'sự ấm áp dễ chịu'."}],[{ko:"공원에 가요",en:"I'm going to the park",zh:"我去公园",vi:"tôi đi công viên",note:"공원 = park.",noteZh:"공원即公园。",noteVi:"공원 = công viên."},{ko:"산책하려고요",en:"I'm planning to take a walk",zh:"我打算散步",vi:"tôi định đi dạo",note:"-(으)려고요 = intending to.",noteZh:"-(으)려고요意为“打算”。",noteVi:"-(으)려고요 nghĩa là 'định làm'."}]],example:{ko:"네, 날씨가 너무 좋아요. 그래서 공원에 가요.",en:"Yes, the weather is so nice. So I'm going to the park.",zh:"是的，天气非常好。所以我去公园。",vi:"Vâng, thời tiết đẹp lắm. Nên tôi đi công viên."},alternatives:[{ko:"내일은 비가 올 것 같아요.",en:"It might rain tomorrow.",zh:"明天好像会下雨。",vi:"Có lẽ ngày mai sẽ mưa.",note:"-(으)ㄹ 것 같아요 = it seems / I think.",noteZh:"-(으)ㄹ 것 같아요意为“好像/我觉得”。",noteVi:"-(으)ㄹ 것 같아요 nghĩa là 'có vẻ như/tôi nghĩ'."},{ko:"요즘 날씨가 너무 더워요.",en:"The weather is so hot these days.",zh:"最近天气太热了。",vi:"Dạo này thời tiết nóng quá.",note:"요즘 = these days.",noteZh:"요즘意为“最近”。",noteVi:"요즘 nghĩa là 'dạo này'."}]},{id:"ko-dlg-b1-work-001",level:"B1",situation:"work",context:{ko:"동료가 도움을 요청할 때",en:"When a coworker asks for help",zh:"当同事请求帮忙时",vi:"Khi đồng nghiệp nhờ giúp đỡ"},prompt:{ko:"혹시 이 보고서 좀 같이 봐 주실 수 있어요?",en:"Could you take a look at this report with me?",zh:"您能和我一起看看这份报告吗？",vi:"Anh/chị có thể xem giúp tôi bản báo cáo này được không?"},template:"네, {0}. 지금 {1}.",blanks:[[{ko:"그럼요",en:"of course",zh:"当然可以",vi:"Tất nhiên rồi",note:"Warm, willing agreement.",noteZh:"热情、乐意的应允。",noteVi:"Sự đồng ý nhiệt tình, sẵn lòng."},{ko:"물론이죠",en:"certainly",zh:"那当然",vi:"Đương nhiên rồi",note:"Confident and polite.",noteZh:"自信而礼貌。",noteVi:"Tự tin và lịch sự."}],[{ko:"도와드릴게요",en:"I'll help you (humble)",zh:"我来帮您",vi:"Tôi sẽ giúp anh/chị",note:"드리다 shows respect to the asker.",noteZh:"드리다 体现对请求者的尊敬。",noteVi:"드리다 thể hiện sự tôn trọng đối với người nhờ vả."},{ko:"같이 볼까요",en:"shall we look together",zh:"我们一起看吧",vi:"Cùng xem nhé",note:"Suggests doing it together.",noteZh:"提议一起做。",noteVi:"Đề nghị cùng nhau làm."}]],example:{ko:"네, 그럼요. 지금 도와드릴게요.",en:"Yes, of course. I'll help you now.",zh:"好，当然可以。我现在就帮您。",vi:"Vâng, tất nhiên rồi. Tôi sẽ giúp anh/chị ngay bây giờ."},alternatives:[{ko:"잠깐만요, 이것만 끝내고요.",en:"Just a moment, let me finish this first.",zh:"稍等一下，我先把这个做完。",vi:"Đợi một chút, để tôi làm xong cái này đã.",note:"Polite way to ask them to wait briefly.",noteZh:"礼貌地请对方稍等片刻。",noteVi:"Cách lịch sự để nhờ đối phương chờ một lát."},{ko:"어떤 부분이 어려우세요?",en:"Which part is giving you trouble?",zh:"您是哪部分觉得难呢？",vi:"Phần nào anh/chị thấy khó vậy?",note:"Shows you want to focus on the real problem.",noteZh:"表示想聚焦真正的问题。",noteVi:"Thể hiện mong muốn tập trung vào vấn đề thực sự."}]},{id:"ko-dlg-b1-work-002",level:"B1",situation:"work",context:{ko:"회의에서 의견을 물을 때",en:"When asked for your opinion in a meeting",zh:"在会议上被问及意见时",vi:"Khi được hỏi ý kiến trong cuộc họp"},prompt:{ko:"이 일정에 대해 어떻게 생각하세요?",en:"What do you think about this schedule?",zh:"您对这个日程安排怎么看？",vi:"Anh/chị nghĩ sao về lịch trình này?"},template:"제 생각에는 {0} 것 같아요. {1}.",blanks:[[{ko:"조금 빠듯할",en:"a bit tight",zh:"有点紧",vi:"Hơi gấp",note:"빠듯하다 = barely enough (time/budget).",noteZh:"빠듯하다 = （时间／预算）勉强够。",noteVi:"빠듯하다 = (thời gian/ngân sách) vừa đủ, eo hẹp."},{ko:"괜찮을",en:"fine / okay",zh:"没问题",vi:"Ổn",note:"Neutral agreement.",noteZh:"中性的认可。",noteVi:"Sự đồng tình trung lập."}],[{ko:"마감을 일주일만 미루면 좋겠어요",en:"I'd like to push the deadline by a week",zh:"希望能把截止日期推迟一周",vi:"Tôi mong có thể lùi hạn chót thêm một tuần",note:"-(으)면 좋겠어요 expresses a soft wish.",noteZh:"-(으)면 좋겠어요 表达委婉的愿望。",noteVi:"-(으)면 좋겠어요 diễn đạt một mong muốn nhẹ nhàng."},{ko:"이대로 진행해도 될 것 같아요",en:"I think we can proceed as is",zh:"我觉得就这样进行也可以",vi:"Tôi nghĩ cứ tiến hành như vậy cũng được",note:"이대로 = as it is, in this way.",noteZh:"이대로 = 就这样／照这个样子。",noteVi:"이대로 = cứ như vậy/theo cách này."}]],example:{ko:"제 생각에는 조금 빠듯할 것 같아요. 마감을 일주일만 미루면 좋겠어요.",en:"In my opinion it seems a bit tight. I'd like to push the deadline by a week.",zh:"在我看来时间有点紧。希望能把截止日期推迟一周。",vi:"Theo tôi thì có vẻ hơi gấp. Tôi mong có thể lùi hạn chót thêm một tuần."},alternatives:[{ko:"팀원들과 한번 의논해 볼게요.",en:"Let me discuss it with the team.",zh:"我跟团队成员商量一下。",vi:"Tôi sẽ bàn bạc với các thành viên trong nhóm.",note:"Buys time and shows collaboration.",noteZh:"既争取时间又体现协作。",noteVi:"Vừa tranh thủ thời gian vừa thể hiện tinh thần hợp tác."},{ko:"저는 큰 문제 없다고 봐요.",en:"I don't see any major problem.",zh:"我认为没什么大问题。",vi:"Tôi cho rằng không có vấn đề gì lớn.",note:"-다고 보다 = 'to see/regard that...'.",noteZh:"-다고 보다 = '认为／看作……'。",noteVi:"-다고 보다 = 'cho rằng/xem là...'."}]},{id:"ko-dlg-b1-health-001",level:"B1",situation:"health",context:{ko:"병원에서 증상을 설명할 때",en:"Describing symptoms at the clinic",zh:"在医院描述症状时",vi:"Khi mô tả triệu chứng ở bệnh viện"},prompt:{ko:"어디가 어떻게 불편하세요?",en:"What seems to be the problem?",zh:"您哪里怎么不舒服？",vi:"Anh/chị thấy khó chịu ở đâu và như thế nào?"},template:"{0}부터 {1}.",blanks:[[{ko:"어제",en:"yesterday",zh:"昨天",vi:"Hôm qua",note:"Time + 부터 = 'since/from'.",noteZh:"时间 + 부터 = '从……起'。",noteVi:"Thời gian + 부터 = 'từ...'."},{ko:"사흘 전",en:"three days ago",zh:"三天前",vi:"Ba ngày trước",note:"사흘 = three days (native Korean count).",noteZh:"사흘 = 三天（韩语固有数词）。",noteVi:"사흘 = ba ngày (số đếm thuần Hàn)."}],[{ko:"열이 나고 목이 아파요",en:"I have a fever and a sore throat",zh:"发烧，嗓子也疼",vi:"Tôi bị sốt và đau họng",note:"-고 connects two symptoms naturally.",noteZh:"-고 自然地连接两个症状。",noteVi:"-고 kết nối hai triệu chứng một cách tự nhiên."},{ko:"기침이 심해요",en:"I have a bad cough",zh:"咳嗽得厉害",vi:"Tôi ho rất nặng",note:"심하다 = severe, intense.",noteZh:"심하다 = 严重、剧烈。",noteVi:"심하다 = nghiêm trọng, dữ dội."}]],example:{ko:"어제부터 열이 나고 목이 아파요.",en:"Since yesterday I've had a fever and a sore throat.",zh:"从昨天开始发烧，嗓子也疼。",vi:"Từ hôm qua tôi bị sốt và đau họng."},alternatives:[{ko:"소화가 잘 안 되는 것 같아요.",en:"I don't think I'm digesting well.",zh:"我好像消化不太好。",vi:"Hình như tôi bị khó tiêu.",note:"소화가 안 되다 = to have indigestion.",noteZh:"소화가 안 되다 = 消化不良。",noteVi:"소화가 안 되다 = bị khó tiêu."},{ko:"약을 먹어도 잘 안 나아요.",en:"Even after taking medicine, I'm not getting better.",zh:"就算吃了药也不见好。",vi:"Dù uống thuốc rồi mà vẫn không đỡ.",note:"-아/어도 = 'even if/though'.",noteZh:"-아/어도 = '即使／尽管'。",noteVi:"-아/어도 = 'dù/mặc dù'."}]},{id:"ko-dlg-b1-travel-001",level:"B1",situation:"travel",context:{ko:"길을 물어볼 때",en:"Asking for directions",zh:"问路时",vi:"Khi hỏi đường"},prompt:{ko:"어디 찾으세요? 도와드릴까요?",en:"Are you looking for somewhere? Can I help?",zh:"您在找什么地方吗？需要帮忙吗？",vi:"Anh/chị đang tìm chỗ nào ạ? Tôi giúp được không?"},template:"네, {0} 어떻게 {1}?",blanks:[[{ko:"시청까지",en:"to City Hall",zh:"到市政厅",vi:"Đến tòa thị chính",note:"Destination + 까지 = 'all the way to'.",noteZh:"目的地 + 까지 = '一直到'。",noteVi:"Điểm đến + 까지 = 'cho đến tận'."},{ko:"이 주소로",en:"to this address",zh:"去这个地址",vi:"Đến địa chỉ này",note:"주소 = address; 로 marks direction.",noteZh:"주소 = 地址；로 表示方向。",noteVi:"주소 = địa chỉ; 로 đánh dấu hướng đi."}],[{ko:"가는지 알 수 있을까요",en:"could I find out how to get there",zh:"能告诉我怎么走吗",vi:"có thể cho tôi biết đi thế nào không",note:"-는지 알 수 있을까요 = a polite indirect question.",noteZh:"-는지 알 수 있을까요 = 礼貌的间接疑问。",noteVi:"-는지 알 수 있을까요 = câu hỏi gián tiếp lịch sự."},{ko:"가면 되나요",en:"should I go / is it the way to go",zh:"该怎么走呢",vi:"đi vậy có được không",note:"-(으)면 되나요 = 'is it okay if I...'.",noteZh:"-(으)면 되나요 = '这样做可以吗'。",noteVi:"-(으)면 되나요 = 'làm vậy có được không'."}]],example:{ko:"네, 시청까지 어떻게 가는지 알 수 있을까요?",en:"Yes, could I find out how to get to City Hall?",zh:"是的，能告诉我到市政厅怎么走吗？",vi:"Vâng, anh/chị có thể cho tôi biết đến tòa thị chính đi thế nào không?"},alternatives:[{ko:"여기에서 먼가요?",en:"Is it far from here?",zh:"离这里远吗？",vi:"Từ đây có xa không?",note:"먼가요 from 멀다 (to be far).",noteZh:"먼가요 来自 멀다（远）。",noteVi:"먼가요 xuất phát từ 멀다 (xa)."},{ko:"걸어서 갈 수 있어요?",en:"Can I get there on foot?",zh:"走着能到吗？",vi:"Đi bộ có tới được không?",note:"걸어서 = on foot, by walking.",noteZh:"걸어서 = 步行、走着。",noteVi:"걸어서 = đi bộ."}]},{id:"ko-dlg-b1-feelings-001",level:"B1",situation:"feelings",context:{ko:"친구가 힘든 일을 털어놓을 때",en:"When a friend shares something difficult",zh:"当朋友倾诉烦心事时",vi:"Khi bạn bè tâm sự chuyện khó khăn"},prompt:{ko:"요즘 일이 너무 안 풀려서 좀 힘들어.",en:"Things haven't been working out lately, so I'm a bit down.",zh:"最近事情很不顺，我有点难受。",vi:"Dạo này mọi việc không suôn sẻ nên tớ hơi mệt mỏi."},template:"{0}. 너무 {1}.",blanks:[[{ko:"그 마음 이해해",en:"I understand how you feel",zh:"我理解你的心情",vi:"Tớ hiểu cảm giác đó",note:"Casual form for a close friend.",noteZh:"对亲近朋友使用的非敬语形式。",noteVi:"Dạng thân mật dùng cho bạn bè thân thiết."},{ko:"많이 속상했겠다",en:"you must have been really upset",zh:"你一定很难过吧",vi:"Chắc là cậu buồn lắm",note:"-겠다 guesses at the other's feeling — shows empathy.",noteZh:"-겠다 推测对方的感受，表达共情。",noteVi:"-겠다 đoán cảm giác của đối phương — thể hiện sự đồng cảm."}],[{ko:"걱정하지 마",en:"don't worry",zh:"别担心",vi:"đừng lo lắng",note:"Reassuring, casual.",noteZh:"安慰的、随意的说法。",noteVi:"Cách nói an ủi, thân mật."},{ko:"힘들어하지 마",en:"don't take it too hard",zh:"别太往心里去",vi:"đừng để trong lòng quá",note:"Pairs with 너무 — 'don't dwell on it too much.'",noteZh:"与 너무 搭配——'别太钻牛角尖'。",noteVi:"Kết hợp với 너무 — 'đừng suy nghĩ quá nhiều về nó'."}]],example:{ko:"많이 속상했겠다. 너무 걱정하지 마.",en:"You must have been really upset. Don't worry too much.",zh:"你一定很难过吧。别太担心了。",vi:"Chắc là cậu buồn lắm. Đừng lo lắng quá."},alternatives:[{ko:"필요하면 언제든 얘기해.",en:"Talk to me anytime you need to.",zh:"需要的话随时找我聊。",vi:"Cần gì thì cứ nói với tớ bất cứ lúc nào.",note:"언제든 = anytime; warm offer of support.",noteZh:"언제든 = 随时；温暖的支持表态。",noteVi:"언제든 = bất cứ lúc nào; lời đề nghị hỗ trợ ấm áp."},{ko:"다 잘될 거야.",en:"Everything will work out.",zh:"一切都会好起来的。",vi:"Mọi chuyện rồi sẽ ổn thôi.",note:"-(으)ㄹ 거야 = casual future 'will'.",noteZh:"-(으)ㄹ 거야 = 非敬语的将来时'会'。",noteVi:"-(으)ㄹ 거야 = thì tương lai 'sẽ' ở dạng thân mật."}]},{id:"ko-dlg-b1-appointment-001",level:"B1",situation:"appointment",context:{ko:"약속을 미뤄야 할 때",en:"When you need to reschedule",zh:"当你需要改约时",vi:"Khi cần dời lịch hẹn"},prompt:{ko:"내일 약속, 그대로 괜찮으시죠?",en:"Tomorrow's appointment is still fine, right?",zh:"明天的约会照旧没问题吧？",vi:"Lịch hẹn ngày mai vẫn giữ nguyên được chứ ạ?"},template:"죄송한데, {0} 약속을 {1}?",blanks:[[{ko:"갑자기 일이 생겨서",en:"because something suddenly came up",zh:"因为突然有事",vi:"vì đột nhiên có việc",note:"Gives a polite reason before the request.",noteZh:"在提出请求前先给出礼貌的理由。",noteVi:"Đưa ra lý do lịch sự trước khi nhờ vả."},{ko:"몸이 안 좋아서",en:"because I'm not feeling well",zh:"因为身体不舒服",vi:"vì cơ thể không khỏe",note:"몸이 안 좋다 = to feel unwell.",noteZh:"몸이 안 좋다 = 身体不适。",noteVi:"몸이 안 좋다 = cảm thấy không khỏe."}],[{ko:"다음 주로 미뤄도 될까요",en:"could we push it to next week",zh:"能推迟到下周吗",vi:"có thể dời sang tuần sau được không",note:"-아/어도 될까요 = 'would it be okay if...'.",noteZh:"-아/어도 될까요 = '这样做可以吗'。",noteVi:"-아/어도 될까요 = 'làm vậy có được không'."},{ko:"다른 날로 바꿀 수 있을까요",en:"could we change it to another day",zh:"能改到别的日子吗",vi:"có thể đổi sang ngày khác được không",note:"바꾸다 = to change/swap.",noteZh:"바꾸다 = 更改／调换。",noteVi:"바꾸다 = thay đổi/hoán đổi."}]],example:{ko:"죄송한데, 갑자기 일이 생겨서 약속을 다음 주로 미뤄도 될까요?",en:"I'm sorry, but something came up — could we push the appointment to next week?",zh:"不好意思，我突然有事，约会能推迟到下周吗？",vi:"Xin lỗi, tôi đột nhiên có việc, có thể dời lịch hẹn sang tuần sau được không?"},alternatives:[{ko:"언제가 괜찮으신지 알려 주세요.",en:"Please let me know when works for you.",zh:"请告诉我您什么时候方便。",vi:"Xin hãy cho tôi biết khi nào anh/chị thuận tiện.",note:"Hands the choice of time to the other person.",noteZh:"把选择时间的权利交给对方。",noteVi:"Trao quyền chọn thời gian cho đối phương."},{ko:"정말 죄송합니다. 다음에 제가 살게요.",en:"I'm really sorry. I'll treat you next time.",zh:"真的很抱歉。下次我请客。",vi:"Thực sự xin lỗi. Lần sau tôi sẽ mời.",note:"제가 살게요 = 'I'll pay/treat' — a friendly make-up offer.",noteZh:"제가 살게요 = '我请客／我买单'，友好的补偿表示。",noteVi:"제가 살게요 = 'tôi sẽ mời/tôi trả tiền' — lời đề nghị bù đắp thân thiện."}]},{id:"ko-dlg-b2-opinion-001",level:"B2",situation:"opinion",context:{ko:"토론 중 상대 의견에 부분적으로 반박",en:"Partly pushing back on someone's view in a discussion",zh:"在讨论中对对方的观点部分反驳",vi:"Phản bác một phần ý kiến của đối phương trong khi thảo luận"},prompt:{ko:"재택근무가 생산성을 떨어뜨린다고 생각해요.",en:"I think working from home lowers productivity.",zh:"我认为居家办公会降低生产率。",vi:"Tôi nghĩ làm việc tại nhà làm giảm năng suất."},template:"{0} {1}, 저는 오히려 효율이 높아진다고 봐요.",blanks:[[{ko:"그 말도 일리가 있지만",en:"that has a point, but",zh:"那话也有道理，但",vi:"lời đó cũng có lý, nhưng",note:"Acknowledges merit before disagreeing — diplomatic.",noteZh:"在表示不同意之前先承认对方有道理——很委婉。",noteVi:"Thừa nhận điểm hợp lý trước khi bày tỏ không đồng ý — mang tính ngoại giao, khéo léo."},{ko:"어느 정도 동의하지만",en:"I agree to some extent, but",zh:"在一定程度上同意，但",vi:"tôi đồng ý một phần, nhưng",note:"Concedes partially, softens the counterpoint.",noteZh:"先部分让步，缓和接下来的反驳。",noteVi:"Nhượng bộ một phần, làm dịu đi phản biện sắp đưa ra."}],[{ko:"솔직히 말하면",en:"to be honest",zh:"老实说",vi:"thành thật mà nói",note:"Adds candor; signals a sincere counter-opinion.",noteZh:"增添坦率感，预示一个真诚的相反观点。",noteVi:"Thêm phần thẳng thắn; báo hiệu một ý kiến trái chiều chân thành sắp đến."},{ko:"제 생각에는",en:"in my opinion",zh:"在我看来",vi:"theo tôi nghĩ",note:"Neutral, polite framing of your stance.",noteZh:"中性、礼貌地表达你的立场。",noteVi:"Cách trình bày lập trường một cách trung lập, lịch sự."}]],example:{ko:"그 말도 일리가 있지만 솔직히 말하면, 저는 오히려 효율이 높아진다고 봐요.",en:"That has a point, but to be honest, I actually think efficiency goes up.",zh:"那话也有道理，但老实说，我反而认为效率会提高。",vi:"Lời đó cũng có lý, nhưng thành thật mà nói, tôi lại cho rằng hiệu quả sẽ tăng lên."},alternatives:[{ko:"꼭 그렇다고 보기는 어려워요.",en:"I wouldn't say that's necessarily the case.",zh:"很难说一定是这样。",vi:"Khó mà nói chắc chắn là như vậy.",note:"Gentle, hedged disagreement.",noteZh:"温和、留有余地的不同意。",noteVi:"Cách không đồng ý nhẹ nhàng, có chừa đường lùi."},{ko:"사람마다 다르지 않을까요?",en:"Doesn't it depend on the person?",zh:"这不是因人而异吗？",vi:"Chẳng phải cái đó tùy người hay sao?",note:"Deflects to individual differences to avoid a clash.",noteZh:"把话题引向个体差异，以避免正面冲突。",noteVi:"Hướng chủ đề sang sự khác biệt cá nhân để tránh xung đột trực tiếp."}]},{id:"ko-dlg-b2-opinion-002",level:"B2",situation:"opinion",context:{ko:"의견을 묻는 질문에 근거와 함께 답하기",en:"Answering an opinion question with reasons",zh:"对征询意见的提问，连同理由一起回答",vi:"Trả lời câu hỏi xin ý kiến kèm theo lý do"},prompt:{ko:"이 정책에 대해 어떻게 생각하세요?",en:"What do you think about this policy?",zh:"您对这项政策怎么看？",vi:"Bạn nghĩ sao về chính sách này?"},template:"저는 {0}. 그 이유는 {1} 때문이에요.",blanks:[[{ko:"찬성하는 입장이에요",en:"I'm in favor",zh:"我持赞成的立场",vi:"đứng về phía ủng hộ",note:"찬성 = support; 입장 = stance/position.",noteZh:"찬성 = 赞成；입장 = 立场／态度。",noteVi:"찬성 = ủng hộ; 입장 = lập trường/thái độ."},{ko:"반대하는 입장이에요",en:"I'm opposed",zh:"我持反对的立场",vi:"đứng về phía phản đối",note:"반대 = oppose. Same frame, opposite stance.",noteZh:"반대 = 反对。句式相同，立场相反。",noteVi:"반대 = phản đối. Cùng cấu trúc câu, lập trường ngược lại."}],[{ko:"장기적으로 도움이 되기",en:"it helps in the long run",zh:"从长远看有帮助",vi:"vì có ích về lâu dài",note:"장기적으로 = in the long term — a B2 connector.",noteZh:"장기적으로 = 从长远看——B2 常用的连接词。",noteVi:"장기적으로 = về lâu dài — một từ nối thường dùng ở trình độ B2."},{ko:"부작용이 클 수 있기",en:"the side effects could be large",zh:"副作用可能很大",vi:"vì tác dụng phụ có thể lớn",note:"Pairs naturally with the 반대 stance.",noteZh:"与“반대（反对）”的立场自然搭配。",noteVi:"Kết hợp tự nhiên với lập trường 반대 (phản đối)."}]],example:{ko:"저는 찬성하는 입장이에요. 그 이유는 장기적으로 도움이 되기 때문이에요.",en:"I'm in favor. The reason is that it helps in the long run.",zh:"我持赞成的立场。原因是从长远看它有帮助。",vi:"Tôi đứng về phía ủng hộ. Lý do là vì nó có ích về lâu dài."},alternatives:[{ko:"아직 판단하기 이른 것 같아요.",en:"I think it's too early to judge.",zh:"我觉得现在下判断还为时过早。",vi:"Tôi nghĩ còn quá sớm để đánh giá.",note:"Polite way to withhold a firm opinion.",noteZh:"礼貌地暂不表明明确观点的说法。",noteVi:"Cách nói lịch sự để tạm chưa đưa ra ý kiến rõ ràng."},{ko:"조금 더 지켜봐야 할 것 같아요.",en:"I think we need to wait and see a bit more.",zh:"我觉得还得再观望一阵。",vi:"Tôi nghĩ cần phải quan sát thêm một chút nữa.",note:"지켜보다 = to watch how things unfold.",noteZh:"지켜보다 = 观察事态如何发展。",noteVi:"지켜보다 = quan sát xem sự việc diễn biến ra sao."}]},{id:"ko-dlg-b2-news-001",level:"B2",situation:"news",context:{ko:"최근 뉴스에 대해 반응하기",en:"Reacting to a recent news story",zh:"对近期新闻作出回应",vi:"Phản ứng trước một tin tức gần đây"},prompt:{ko:"그 사건이 큰 논란이 됐다고 하던데요.",en:"I heard that incident became a big controversy.",zh:"听说那起事件引发了很大的争议。",vi:"Nghe nói sự việc đó đã trở thành một tranh cãi lớn."},template:"네, {0}. {1} 찬반이 갈리는 것 같아요.",blanks:[[{ko:"보도에 따르면 심각한 상황이래요",en:"according to reports, it's serious",zh:"据报道情况很严重",vi:"theo báo cáo thì tình hình nghiêm trọng",note:"보도에 따르면 = 'according to reports,' newsy register.",noteZh:"보도에 따르면 = “据报道”，新闻语体。",noteVi:"보도에 따르면 = “theo báo cáo”, văn phong báo chí."},{ko:"여론이 많이 안 좋아졌어요",en:"public opinion has soured a lot",zh:"舆论变得很不好",vi:"dư luận đã trở nên rất xấu",note:"여론 = public opinion — a core news word.",noteZh:"여론 = 舆论——核心新闻词汇。",noteVi:"여론 = dư luận — từ vựng cốt lõi trong tin tức."}],[{ko:"이 문제를 두고",en:"over this issue",zh:"围绕这个问题",vi:"xoay quanh vấn đề này",note:"...을 두고 = 'over (a contested issue).'",noteZh:"……을 두고 = “围绕（有争议的议题）”。",noteVi:"...을 두고 = “xoay quanh (một vấn đề đang gây tranh cãi)”."},{ko:"사람들 사이에서",en:"among people",zh:"在人们之间",vi:"giữa mọi người với nhau",note:"More everyday phrasing for the same idea.",noteZh:"表达同样意思的更日常的说法。",noteVi:"Cách diễn đạt đời thường hơn cho cùng một ý."}]],example:{ko:"네, 보도에 따르면 심각한 상황이래요. 이 문제를 두고 찬반이 갈리는 것 같아요.",en:"Yes, according to reports it's serious. Opinions seem split for and against over this issue.",zh:"是啊，据报道情况很严重。围绕这个问题，大家似乎赞成与反对意见不一。",vi:"Vâng, theo báo cáo thì tình hình nghiêm trọng. Có vẻ ý kiến đang chia rẽ giữa tán thành và phản đối xoay quanh vấn đề này."},alternatives:[{ko:"당국이 곧 입장을 밝힐 것 같아요.",en:"The authorities will probably state their position soon.",zh:"当局大概很快会表明立场。",vi:"Có lẽ nhà chức trách sẽ sớm nêu rõ lập trường.",note:"입장을 밝히다 = to clarify one's official stance.",noteZh:"입장을 밝히다 = 表明自己的官方立场。",noteVi:"입장을 밝히다 = làm rõ lập trường chính thức của mình."},{ko:"여파가 한동안 이어질 것 같아요.",en:"The repercussions will likely continue for a while.",zh:"余波可能会持续一段时间。",vi:"Có lẽ dư chấn sẽ còn tiếp diễn một thời gian.",note:"여파 = aftermath; 이어지다 = to continue.",noteZh:"여파 = 余波；이어지다 = 持续。",noteVi:"여파 = dư chấn; 이어지다 = tiếp diễn/kéo dài."}]},{id:"ko-dlg-b2-environment-001",level:"B2",situation:"environment",context:{ko:"환경 보호 실천에 대해 이야기",en:"Talking about taking eco-friendly action",zh:"谈论践行环保的话题",vi:"Nói chuyện về việc thực hành bảo vệ môi trường"},prompt:{ko:"요즘 환경을 위해 따로 실천하는 게 있어요?",en:"Are you doing anything in particular for the environment these days?",zh:"最近你有没有特别为环境做些什么？",vi:"Dạo này bạn có làm gì riêng cho môi trường không?"},template:"네, {0} 줄이려고 노력하고, {1} 신경 써요.",blanks:[[{ko:"일회용품 사용을",en:"the use of disposables",zh:"一次性用品的使用",vi:"việc sử dụng đồ dùng một lần",note:"일회용품 = single-use items, a real Korean policy topic.",noteZh:"일회용품 = 一次性用品，是韩国现实中的一个政策话题。",noteVi:"일회용품 = đồ dùng một lần, một chủ đề chính sách có thật ở Hàn Quốc."},{ko:"탄소 배출을",en:"carbon emissions",zh:"碳排放",vi:"phát thải carbon",note:"More formal, bigger-picture framing.",noteZh:"更正式、更宏观的说法。",noteVi:"Cách nói trang trọng hơn, mang tính bao quát hơn."}],[{ko:"분리수거에도",en:"to separating recycling too",zh:"对垃圾分类也",vi:"cả việc phân loại rác nữa",note:"분리수거 = sorting recycling — daily life in Korea.",noteZh:"분리수거 = 垃圾分类回收——韩国的日常生活。",noteVi:"분리수거 = phân loại rác để tái chế — sinh hoạt hàng ngày ở Hàn Quốc."},{ko:"친환경 제품에도",en:"to eco-friendly products too",zh:"对环保产品也",vi:"cả sản phẩm thân thiện môi trường nữa",note:"친환경 = eco-friendly, attaches to nouns.",noteZh:"친환경 = 环保，用于修饰名词。",noteVi:"친환경 = thân thiện với môi trường, gắn với danh từ."}]],example:{ko:"네, 일회용품 사용을 줄이려고 노력하고, 분리수거에도 신경 써요.",en:"Yes, I try to cut down on disposables, and I'm careful about sorting recycling too.",zh:"嗯，我尽量减少一次性用品的使用，也很注意垃圾分类。",vi:"Vâng, tôi cố gắng giảm sử dụng đồ dùng một lần, và cũng chú ý đến việc phân loại rác."},alternatives:[{ko:"작은 일이라도 실천하는 게 중요하니까요.",en:"Because it matters to act, even on small things.",zh:"因为哪怕是小事，付诸行动也很重要。",vi:"Vì dù là việc nhỏ, hành động thực tế cũng quan trọng mà.",note:"실천하다 = to put into practice — key eco verb.",noteZh:"실천하다 = 付诸实践——关键的环保动词。",noteVi:"실천하다 = biến thành hành động thực tế — động từ chủ chốt trong chủ đề môi trường."},{ko:"대중교통을 주로 이용하려고 해요.",en:"I try to mainly use public transport.",zh:"我尽量主要乘坐公共交通。",vi:"Tôi cố gắng chủ yếu sử dụng phương tiện công cộng.",note:"대중교통 = public transit; a concrete habit.",noteZh:"대중교통 = 公共交通；一个具体的习惯。",noteVi:"대중교통 = phương tiện giao thông công cộng; một thói quen cụ thể."}]},{id:"ko-dlg-b2-technology-001",level:"B2",situation:"technology",context:{ko:"인공지능의 영향에 대해 토론",en:"Discussing the impact of AI",zh:"讨论人工智能的影响",vi:"Thảo luận về ảnh hưởng của trí tuệ nhân tạo"},prompt:{ko:"인공지능이 결국 사람 일자리를 다 없앨까요?",en:"Will AI ultimately wipe out all human jobs?",zh:"人工智能最终会把人的工作岗位全都消灭掉吗？",vi:"Cuối cùng trí tuệ nhân tạo có xóa sổ hết việc làm của con người không?"},template:"글쎄요, {0}. 다만 {1} 부작용도 무시할 수는 없어요.",blanks:[[{ko:"완전히 대체하기는 어렵다고 봐요",en:"I think it's hard to fully replace people",zh:"我认为很难完全取代人",vi:"tôi cho rằng khó mà thay thế hoàn toàn",note:"대체하다 = to replace; -다고 봐요 = 'I take the view that.'",noteZh:"대체하다 = 取代；-다고 봐요 = “我认为／我持……的看法”。",noteVi:"대체하다 = thay thế; -다고 봐요 = “tôi cho rằng / tôi có quan điểm rằng”."},{ko:"오히려 새 일자리도 생길 거예요",en:"new jobs will appear, if anything",zh:"反而还会催生新的工作岗位",vi:"ngược lại còn sẽ sinh ra việc làm mới",note:"오히려 = 'if anything / on the contrary.'",noteZh:"오히려 = “反而／恰恰相反”。",noteVi:"오히려 = “ngược lại / trái lại”."}],[{ko:"지나치게 의존하는",en:"relying on it too much",zh:"过度依赖",vi:"phụ thuộc quá mức",note:"...에 의존하다 = to depend on; 지나치게 = excessively.",noteZh:"……에 의존하다 = 依赖；지나치게 = 过度地。",noteVi:"...에 의존하다 = phụ thuộc vào; 지나치게 = một cách quá mức."},{ko:"정보 격차가 커지는",en:"the information gap widening",zh:"信息鸿沟扩大",vi:"khoảng cách thông tin ngày càng lớn",note:"정보 격차 = the digital/information divide.",noteZh:"정보 격차 = 数字／信息鸿沟。",noteVi:"정보 격차 = khoảng cách số/thông tin."}]],example:{ko:"글쎄요, 완전히 대체하기는 어렵다고 봐요. 다만 지나치게 의존하는 부작용도 무시할 수는 없어요.",en:"Well, I think it's hard to fully replace people. That said, we can't ignore the downside of relying on it too much.",zh:"这个嘛，我认为很难完全取代人。不过过度依赖的副作用也不容忽视。",vi:"Ừm, tôi cho rằng khó mà thay thế hoàn toàn con người. Nhưng cũng không thể bỏ qua tác dụng phụ của việc phụ thuộc quá mức."},alternatives:[{ko:"기술 변화 속도를 따라가기가 벅차요.",en:"It's overwhelming to keep up with the pace of tech change.",zh:"要跟上技术变化的速度很吃力。",vi:"Theo kịp tốc độ thay đổi công nghệ thật đuối sức.",note:"따라가다 = to keep up; 벅차다 = overwhelming.",noteZh:"따라가다 = 跟上；벅차다 = 吃力／力不从心。",noteVi:"따라가다 = theo kịp; 벅차다 = quá sức/đuối sức."},{ko:"결국 사람의 역할이 바뀌는 거겠죠.",en:"In the end, the human role will just shift.",zh:"归根结底，人的角色只是会发生转变吧。",vi:"Rốt cuộc thì vai trò của con người chỉ là sẽ thay đổi thôi.",note:"Frames change as transformation, not elimination.",noteZh:"把变化诠释为转型，而非被淘汰。",noteVi:"Diễn giải sự thay đổi như một sự chuyển đổi, chứ không phải bị đào thải."}]},{id:"ko-dlg-b2-culture-001",level:"B2",situation:"culture",context:{ko:"전시나 공연 추천하기",en:"Recommending an exhibition or performance",zh:"推荐展览或演出",vi:"Giới thiệu triển lãm hoặc buổi biểu diễn"},prompt:{ko:"주말에 볼 만한 전시 있을까요?",en:"Is there an exhibition worth seeing this weekend?",zh:"周末有什么值得一看的展览吗？",vi:"Cuối tuần có triển lãm nào đáng xem không?"},template:"네, {0}. 작가의 {1} 잘 드러나서 가 볼 만해요.",blanks:[[{ko:"요즘 하는 사진전을 추천해요",en:"I recommend the photo exhibition on now",zh:"我推荐最近在办的摄影展",vi:"tôi giới thiệu triển lãm ảnh đang diễn ra dạo này",note:"사진전 = photography exhibition; 추천하다 = to recommend.",noteZh:"사진전 = 摄影展；추천하다 = 推荐。",noteVi:"사진전 = triển lãm ảnh; 추천하다 = giới thiệu/gợi ý."},{ko:"근처 미술관 전시가 좋았어요",en:"the show at the nearby museum was good",zh:"附近美术馆的展览很不错",vi:"triển lãm ở bảo tàng mỹ thuật gần đây khá hay",note:"미술관 = art museum/gallery.",noteZh:"미술관 = 美术馆／画廊。",noteVi:"미술관 = bảo tàng/phòng trưng bày mỹ thuật."}],[{ko:"개성이",en:"individuality",zh:"个性",vi:"cá tính",note:"개성 = a distinct personal style.",noteZh:"개성 = 与众不同的个人风格。",noteVi:"개성 = phong cách cá nhân riêng biệt."},{ko:"감각이",en:"artistic sensibility",zh:"艺术感觉",vi:"cảm quan nghệ thuật",note:"감각 = a refined sense/feel for things.",noteZh:"감각 = 对事物细腻的感觉／审美。",noteVi:"감각 = cảm nhận/óc thẩm mỹ tinh tế về sự vật."}]],example:{ko:"네, 요즘 하는 사진전을 추천해요. 작가의 개성이 잘 드러나서 가 볼 만해요.",en:"Yes, I recommend the photo exhibition on now. The artist's individuality really shows, so it's worth going.",zh:"嗯，我推荐最近在办的摄影展。作者的个性展现得很充分，值得一看。",vi:"Vâng, tôi giới thiệu triển lãm ảnh đang diễn ra dạo này. Cá tính của tác giả thể hiện rất rõ nên đáng để xem."},alternatives:[{ko:"취향에 따라 다르겠지만 저는 좋았어요.",en:"It depends on your taste, but I liked it.",zh:"虽然因人的喜好而异，但我挺喜欢的。",vi:"Tùy vào sở thích mỗi người, nhưng tôi thì thích.",note:"취향 = taste/preference; hedges a recommendation.",noteZh:"취향 = 喜好／品味；给推荐留有余地。",noteVi:"취향 = sở thích/gu; giúp lời giới thiệu có chừa đường lùi."},{ko:"인상 깊은 작품이 많았어요.",en:"There were many impressive pieces.",zh:"有很多令人印象深刻的作品。",vi:"Có nhiều tác phẩm để lại ấn tượng sâu sắc.",note:"인상 깊다 = to leave a deep impression; 작품 = work.",noteZh:"인상 깊다 = 印象深刻；작품 = 作品。",noteVi:"인상 깊다 = để lại ấn tượng sâu sắc; 작품 = tác phẩm."}]},{id:"ko-dlg-c1-business-001",level:"C1",situation:"business",context:{ko:"회의에서 제안에 신중하게 답하기",en:"Responding cautiously to a proposal in a meeting",zh:"在会议上谨慎地回应提案",vi:"Trả lời thận trọng trước một đề xuất trong cuộc họp"},prompt:{ko:"이번 분기 안에 신규 사업을 추진하는 게 어떻겠습니까?",en:"How about pushing ahead with the new project within this quarter?",zh:"本季度内推进新业务，您看怎么样？",vi:"Chúng ta xúc tiến dự án kinh doanh mới trong quý này thì thế nào?"},template:"{0} 검토가 필요하지만, {1} 긍정적으로 {2}.",blanks:[[{ko:"추가적인",en:"additional",zh:"额外的",vi:"bổ sung",note:"추가적 (additional, 追加的) sounds measured and formal.",noteZh:"추가적（额外的、追加的，追加的）语气稳重而正式。",noteVi:"추가적 (bổ sung, thêm vào) nghe có vẻ thận trọng và trang trọng."},{ko:"면밀한",en:"careful / thorough",zh:"缜密的",vi:"kỹ lưỡng",note:"면밀하다 (meticulous, 綿密) emphasizes due diligence.",noteZh:"면밀하다（缜密，綿密）强调审慎周全。",noteVi:"면밀하다 (kỹ lưỡng, tỉ mỉ) nhấn mạnh sự thận trọng, chu đáo."}],[{ko:"방향 자체는",en:"the direction itself",zh:"方向本身",vi:"bản thân hướng đi",note:"Concedes the overall idea while reserving on details.",noteZh:"认可整体思路，但对细节保留意见。",noteVi:"Thừa nhận ý tưởng tổng thể nhưng vẫn bảo lưu ý kiến về chi tiết."},{ko:"취지에는",en:"as for the intent",zh:"就宗旨而言",vi:"về mục đích thì",note:"취지 (intent/purpose, 趣旨) — agreeing with the aim.",noteZh:"취지（宗旨、意图，趣旨）——赞同其目标。",noteVi:"취지 (mục đích, tôn chỉ) — đồng ý với mục tiêu đề ra."}],[{ko:"검토하겠습니다",en:"will review it",zh:"会研究一下",vi:"sẽ xem xét",note:"Polite, non-committal commitment to consider.",noteZh:"礼貌、不作承诺地表示会考虑。",noteVi:"Một cam kết lịch sự nhưng không ràng buộc, chỉ hứa sẽ cân nhắc."},{ko:"보고 있습니다",en:"am viewing it",zh:"正持某种看法",vi:"đang nhìn nhận",note:"긍정적으로 보다 = to view favorably.",noteZh:"긍정적으로 보다 = 持肯定看法。",noteVi:"긍정적으로 보다 = nhìn nhận một cách tích cực."}]],example:{ko:"추가적인 검토가 필요하지만, 방향 자체는 긍정적으로 검토하겠습니다.",en:"It needs additional review, but I'll consider the direction itself favorably.",zh:"虽然还需要进一步研究，但方向本身我会积极考虑。",vi:"Cần xem xét thêm, nhưng bản thân hướng đi thì tôi sẽ xem xét một cách tích cực."},alternatives:[{ko:"득실을 좀 더 따져 봐야 할 것 같습니다.",en:"I think we need to weigh the pros and cons a bit more.",zh:"我觉得还需要再权衡一下得失。",vi:"Tôi nghĩ chúng ta cần cân nhắc kỹ hơn về được mất.",note:"Buys time analytically without rejecting the idea.",noteZh:"以分析为由争取时间，又不否定该想法。",noteVi:"Tranh thủ thêm thời gian bằng lý do phân tích, mà không phủ nhận ý tưởng đó."},{ko:"후속 미팅에서 구체적으로 논의하시죠.",en:"Let's discuss the specifics in a follow-up meeting.",zh:"具体细节我们在后续会议上讨论吧。",vi:"Chúng ta hãy bàn cụ thể trong cuộc họp tiếp theo.",note:"Defers detail politely to a later session.",noteZh:"礼貌地把细节留到之后的会议。",noteVi:"Lịch sự để chi tiết lại bàn vào buổi họp sau."}]},{id:"ko-dlg-c1-business-002",level:"C1",situation:"business",context:{ko:"프로젝트 차질에 대한 책임을 다루기",en:"Addressing accountability for a project setback",zh:"处理项目失误的责任问题",vi:"Xử lý trách nhiệm về sự cố của dự án"},prompt:{ko:"일정이 많이 지연됐는데, 원인이 무엇이라고 보십니까?",en:"The schedule has slipped a lot — what do you see as the cause?",zh:"进度延误了很多，您认为原因是什么？",vi:"Tiến độ đã bị chậm khá nhiều, anh/chị nhận định nguyên nhân là gì?"},template:"{0} 제 판단 착오였고, 결과에 대해서는 제가 {1}.",blanks:[[{ko:"솔직히 말씀드리면",en:"to be honest",zh:"坦白地说",vi:"nói thẳng ra thì",note:"Frank but professional opener for owning a mistake.",noteZh:"坦率却不失专业，用于主动承认错误的开场。",noteVi:"Mở đầu thẳng thắn nhưng vẫn chuyên nghiệp khi chủ động thừa nhận sai sót."},{ko:"변명의 여지 없이",en:"without excuse",zh:"毫无借口地",vi:"không có gì để biện minh",note:"변명의 여지 없이 = leaving no room for excuses. Strong accountability.",noteZh:"변명의 여지 없이 = 没有辩解的余地。表示强烈的担当。",noteVi:"변명의 여지 없이 = không còn chỗ để biện hộ. Thể hiện tinh thần trách nhiệm mạnh mẽ."}],[{ko:"책임을 지겠습니다",en:"will take responsibility",zh:"我会承担责任",vi:"sẽ chịu trách nhiệm",note:"책임을 지다 = to bear responsibility. Valued highly in Korean work culture.",noteZh:"책임을 지다 = 承担责任。在韩国职场文化中备受推崇。",noteVi:"책임을 지다 = gánh chịu trách nhiệm. Rất được coi trọng trong văn hóa công sở Hàn Quốc."},{ko:"책임을 통감합니다",en:"feel the responsibility keenly",zh:"我深感责任重大",vi:"cảm nhận sâu sắc trách nhiệm",note:"통감하다 (to feel acutely, 痛感) — formal, contrite register.",noteZh:"통감하다（深感、痛感，痛感）——正式而带歉意的语气。",noteVi:"통감하다 (cảm nhận sâu sắc, thấm thía) — văn phong trang trọng, mang ý hối lỗi."}]],example:{ko:"솔직히 말씀드리면 제 판단 착오였고, 결과에 대해서는 제가 책임을 지겠습니다.",en:"To be honest, it was my misjudgment, and I will take responsibility for the outcome.",zh:"坦白地说，是我判断失误，对于结果我会承担责任。",vi:"Nói thẳng ra thì đó là sai lầm trong phán đoán của tôi, và tôi sẽ chịu trách nhiệm về kết quả này."},alternatives:[{ko:"재발 방지책을 마련하겠습니다.",en:"I'll put measures in place to prevent a recurrence.",zh:"我会制定防止再次发生的措施。",vi:"Tôi sẽ chuẩn bị biện pháp phòng ngừa tái diễn.",note:"재발 방지 (recurrence prevention, 再發防止) — shows forward-looking ownership.",noteZh:"재발 방지（防止再次发生，再發防止）——体现着眼未来的担当。",noteVi:"재발 방지 (phòng ngừa tái diễn) — thể hiện tinh thần trách nhiệm hướng tới tương lai."},{ko:"원인을 면밀히 분석해 보고드리겠습니다.",en:"I'll analyze the cause closely and report back.",zh:"我会仔细分析原因后再向您汇报。",vi:"Tôi sẽ phân tích kỹ nguyên nhân rồi báo cáo lại.",note:"Defers blame to a fact-based follow-up.",noteZh:"把追责引向以事实为依据的后续跟进。",noteVi:"Hướng việc quy trách nhiệm sang một bước theo dõi dựa trên sự thật."}]},{id:"ko-dlg-c1-society-001",level:"C1",situation:"society",context:{ko:"사회 격차 문제에 의견을 밝히기",en:"Stating your view on social inequality",zh:"就社会差距问题表明看法",vi:"Nêu quan điểm về vấn đề bất bình đẳng xã hội"},prompt:{ko:"빈부 격차 문제, 정부가 어떻게 접근해야 한다고 보세요?",en:"How do you think the government should approach the wealth gap?",zh:"对于贫富差距问题，您认为政府应该如何应对？",vi:"Về vấn đề khoảng cách giàu nghèo, anh/chị nghĩ chính phủ nên tiếp cận như thế nào?"},template:"단기 대책보다는 {0} 사회 안전망을 {1} 하고, 무엇보다 {2} 형성이 우선이라고 봅니다.",blanks:[[{ko:"근본적으로",en:"fundamentally",zh:"从根本上",vi:"về căn bản",note:"근본적 (fundamental, 根本的) frames a structural rather than quick fix.",noteZh:"근본적（根本的，根本的）强调结构性解决而非临时补救。",noteVi:"근본적 (căn bản, cốt lõi) nhấn mạnh giải pháp mang tính cấu trúc thay vì đối phó tạm thời."},{ko:"장기적으로",en:"in the long term",zh:"从长远来看",vi:"về lâu dài",note:"장기적 (long-term, 長期的) signals sustained policy.",noteZh:"장기적（长期的，長期的）意味着持续性的政策。",noteVi:"장기적 (dài hạn) hàm ý một chính sách mang tính bền vững."}],[{ko:"강화해야",en:"must strengthen",zh:"必须强化",vi:"phải củng cố",note:"강화하다 (to reinforce, 強化) pairs with 안전망 (safety net).",noteZh:"강화하다（强化，強化）与 안전망（保障网）搭配。",noteVi:"강화하다 (củng cố, tăng cường) thường đi kèm với 안전망 (mạng lưới an sinh)."},{ko:"촘촘히 해야",en:"must make denser / tighter",zh:"必须织得更密",vi:"phải dệt cho dày, khít hơn",note:"촘촘히 = densely; vivid way to describe a fine-meshed safety net.",noteZh:"촘촘히 = 密密地；生动地形容把保障网织得更细密。",noteVi:"촘촘히 = một cách dày đặc, khít khao; cách diễn đạt sinh động để mô tả việc dệt mạng lưới an sinh chặt chẽ hơn."}],[{ko:"사회적 공감대",en:"public consensus",zh:"社会共识",vi:"sự đồng cảm chung trong xã hội",note:"공감대 형성 = building common ground, prerequisite for reform.",noteZh:"공감대 형성 = 凝聚共识，是改革的前提。",noteVi:"공감대 형성 = hình thành sự đồng cảm chung, điều kiện tiên quyết cho cải cách."},{ko:"정책적 합의",en:"policy consensus",zh:"政策共识",vi:"sự đồng thuận về chính sách",note:"합의 (agreement, 合意) at the policy level.",noteZh:"합의（合意、共识，合意）在政策层面上的达成。",noteVi:"합의 (thỏa thuận, đồng thuận) đạt được ở cấp độ chính sách."}]],example:{ko:"단기 대책보다는 근본적으로 사회 안전망을 강화해야 하고, 무엇보다 사회적 공감대 형성이 우선이라고 봅니다.",en:"Rather than short-term measures, we must fundamentally strengthen the social safety net, and above all, building public consensus comes first.",zh:"比起短期对策，更应从根本上强化社会保障网，而最重要的是先凝聚社会共识。",vi:"Thay vì các đối sách ngắn hạn, tôi cho rằng cần củng cố mạng lưới an sinh xã hội một cách căn bản, và trên hết, việc hình thành sự đồng cảm chung trong xã hội phải được ưu tiên."},alternatives:[{ko:"취약 계층에 대한 지원을 우선해야 합니다.",en:"Support for vulnerable groups should come first.",zh:"应当优先扶持弱势群体。",vi:"Cần ưu tiên hỗ trợ các nhóm yếu thế.",note:"취약 계층 (vulnerable groups, 脆弱階層) — a common policy target.",noteZh:"취약 계층（弱势群体，脆弱階層）——常见的政策扶持对象。",noteVi:"취약 계층 (nhóm yếu thế) — đối tượng thường được nhắm tới trong chính sách hỗ trợ."},{ko:"세대 간 형평성도 함께 고려해야 합니다.",en:"Intergenerational fairness must also be considered.",zh:"还须一并考虑代际之间的公平。",vi:"Cũng cần xem xét đồng thời sự công bằng giữa các thế hệ.",note:"형평성 (equity, 衡平性) broadens the framing.",noteZh:"형평성（公平、衡平，衡平性）拓宽了问题的视野。",noteVi:"형평성 (tính công bằng) mở rộng góc nhìn của vấn đề."}]},{id:"ko-dlg-c1-abstract-001",level:"C1",situation:"abstract",context:{ko:"상대 주장의 논리를 점잖게 반박하기",en:"Politely rebutting the logic of someone's argument",zh:"礼貌地反驳对方论点的逻辑",vi:"Nhã nhặn phản biện logic trong lập luận của đối phương"},prompt:{ko:"규제를 풀면 경제가 무조건 살아난다고 보는데, 동의하시죠?",en:"I believe deregulation will definitely revive the economy — you agree, right?",zh:"我认为放松管制经济就一定会复苏，您同意吧？",vi:"Tôi cho rằng nếu nới lỏng quản lý thì kinh tế chắc chắn sẽ hồi phục, anh/chị đồng ý chứ?"},template:"취지에는 공감하지만, 그 결론은 {0} {1} 있다고 봅니다.",blanks:[[{ko:"전제에서 결론으로 가는 과정에",en:"in the step from premise to conclusion",zh:"在从前提到结论的过程中",vi:"trong quá trình đi từ tiền đề đến kết luận",note:"Pinpoints exactly where the reasoning is weak.",noteZh:"精准指出推理薄弱的环节。",noteVi:"Chỉ ra chính xác điểm mà lập luận còn yếu."},{ko:"근거가 부족해",en:"lacking in evidence",zh:"论据不足",vi:"thiếu căn cứ",note:"근거 (grounds, 根據) — challenges the evidential basis.",noteZh:"근거（论据、根据，根據）——质疑其证据基础。",noteVi:"근거 (căn cứ) — đặt nghi vấn về cơ sở chứng cứ của lập luận."}],[{ko:"다소 비약이",en:"somewhat of a logical leap",zh:"略有逻辑跳跃",vi:"có phần khiên cưỡng",note:"비약 (a leap, 飛躍) = jumping to a conclusion. 다소 (somewhat) softens it.",noteZh:"비약（飞跃、跳跃，飛躍）= 妄下结论。다소（略微）起到缓和作用。",noteVi:"비약 (bước nhảy vọt) = vội vàng đi đến kết luận. 다소 (phần nào) làm dịu bớt ý phê phán."},{ko:"논란의 여지가",en:"room for debate",zh:"有争议的余地",vi:"chỗ để tranh cãi",note:"여지 (room/leeway, 餘地) — flags it as contestable.",noteZh:"여지（余地，餘地）——指出其尚有争议。",noteVi:"여지 (dư địa, khoảng trống) — chỉ ra rằng điều đó vẫn còn có thể tranh cãi."}]],example:{ko:"취지에는 공감하지만, 그 결론은 전제에서 결론으로 가는 과정에 다소 비약이 있다고 봅니다.",en:"I sympathize with the intent, but I think that conclusion involves something of a logical leap from premise to conclusion.",zh:"我认同您的宗旨，但我认为那个结论在从前提到结论的过程中略有逻辑跳跃。",vi:"Tôi đồng cảm với mục đích đó, nhưng tôi cho rằng kết luận ấy có phần khiên cưỡng trong quá trình đi từ tiền đề đến kết luận."},alternatives:[{ko:"역으로 말하면 부작용도 함께 고려해야 합니다.",en:"Conversely, we must also consider the side effects.",zh:"反过来说，也必须一并考虑副作用。",vi:"Nói ngược lại, cũng cần phải xem xét đồng thời cả tác dụng phụ.",note:"역으로 (in reverse, 逆) reframes to test the inverse.",noteZh:"역으로（反过来，逆）通过检验反面来重新审视。",noteVi:"역으로 (theo chiều ngược lại) diễn đạt lại vấn đề bằng cách kiểm chứng mặt trái của nó."},{ko:"다른 관점에서 보면 해석이 달라질 수 있습니다.",en:"Viewed from another angle, the interpretation could differ.",zh:"换个角度看，解读可能会有所不同。",vi:"Nhìn từ góc độ khác, cách diễn giải có thể sẽ khác đi.",note:"관점 (viewpoint, 觀點) — invites an alternative reading.",noteZh:"관점（观点，觀點）——引出另一种解读。",noteVi:"관점 (quan điểm, góc nhìn) — mở ra một cách diễn giải khác."}]},{id:"ko-dlg-c1-media-001",level:"C1",situation:"media",context:{ko:"보도 내용을 비판적으로 평가하기",en:"Critically assessing a news report",zh:"批判性地评价报道内容",vi:"Đánh giá nội dung bản tin một cách phê phán"},prompt:{ko:"이 기사 보셨어요? 다들 사실이라고 난리던데요.",en:"Did you see this article? Everyone's in an uproar saying it's true.",zh:"你看过这篇报道吗？大家都吵着说是真的呢。",vi:"Anh/chị xem bài báo này chưa? Mọi người đang xôn xao bảo là chuyện thật đấy."},template:"기사를 {0} 받아들이기보다는 {1} 먼저 {2} 할 것 같아요.",blanks:[[{ko:"곧이곧대로",en:"at face value",zh:"全盘照信",vi:"một cách máy móc",note:"곧이곧대로 = uncritically/literally. A native idiom for naive acceptance.",noteZh:"곧이곧대로 = 不加辨别地、原封不动地。表示轻信的固有惯用语。",noteVi:"곧이곧대로 = không suy xét, y nguyên như vậy. Thành ngữ thuần Hàn diễn tả sự cả tin."},{ko:"그대로",en:"as is",zh:"原样",vi:"y nguyên như vậy",note:"Plainer than 곧이곧대로, still natural here.",noteZh:"比 곧이곧대로 更朴素，在这里同样自然。",noteVi:"Đơn giản hơn so với 곧이곧대로, nhưng vẫn tự nhiên trong ngữ cảnh này."}],[{ko:"사실 관계를",en:"the facts",zh:"事实真相",vi:"tình tiết sự việc",note:"사실 관계 = the factual basis journalists must verify.",noteZh:"사실 관계 = 记者必须核实的事实依据。",noteVi:"사실 관계 = cơ sở sự thật mà nhà báo bắt buộc phải kiểm chứng."},{ko:"출처를",en:"the source",zh:"消息来源",vi:"nguồn tin",note:"출처 (source, 出處) — where the claim originates.",noteZh:"출처（出处、来源，出處）——某说法的源头。",noteVi:"출처 (nguồn gốc, xuất xứ) — nơi bắt nguồn của một thông tin."}],[{ko:"확인해야",en:"should verify",zh:"应当核实",vi:"nên xác minh",note:"확인하다 (to verify) pairs with 사실 관계.",noteZh:"확인하다（核实）与 사실 관계 搭配。",noteVi:"확인하다 (xác minh) thường đi cùng với 사실 관계 (tình tiết sự việc)."},{ko:"따져 봐야",en:"should scrutinize",zh:"应当追究",vi:"nên xem xét kỹ",note:"따지다 = to scrutinize/question critically.",noteZh:"따지다 = 追究、认真质疑。",noteVi:"따지다 = xem xét kỹ, chất vấn nghiêm túc."}]],example:{ko:"기사를 곧이곧대로 받아들이기보다는 사실 관계를 먼저 확인해야 할 것 같아요.",en:"Rather than taking the article at face value, I think we should verify the facts first.",zh:"与其对报道全盘照信，我觉得应该先核实事实真相。",vi:"Thay vì tin ngay bài báo một cách máy móc, tôi nghĩ nên xác minh tình tiết sự việc trước đã."},alternatives:[{ko:"자극적인 제목에 휘둘리면 안 됩니다.",en:"We shouldn't be swayed by a sensational headline.",zh:"不该被耸动的标题牵着走。",vi:"Không nên bị cuốn theo cái tiêu đề giật gân.",note:"자극적 (sensational, 刺戟的) — warns against clickbait framing.",noteZh:"자극적（耸动、刺激性的，刺戟的）——警惕标题党式的手法。",noteVi:"자극적 (giật gân, kích động) — cảnh báo về thủ thuật đặt tiêu đề câu view."},{ko:"특정 프레임이 씌워진 건 아닌지 봐야 해요.",en:"We should check whether a particular frame has been imposed.",zh:"得看看是不是被扣上了某种框架。",vi:"Cần xem liệu có bị gán một khung định kiến nào đó hay không.",note:"프레임을 씌우다 = to impose a narrative frame.",noteZh:"프레임을 씌우다 = 强加某种叙事框架。",noteVi:"프레임을 씌우다 = áp đặt một khung tường thuật nào đó."}]},{id:"ko-dlg-c2-academic-001",level:"C2",situation:"academic",context:{ko:"학회에서 발표자에게 반론을 제기할 때",en:"Raising a counterargument to a presenter at a conference",zh:"在学术会议上向发表者提出反论时",vi:"Đưa ra phản biện với người thuyết trình tại hội nghị học thuật"},prompt:{ko:"제 연구는 이 변수가 결과를 결정한다는 점을 보여 줍니다.",en:"My research shows that this variable determines the outcome.",zh:"我的研究表明，这一变量决定了结果。",vi:"Nghiên cứu của tôi cho thấy biến số này quyết định kết quả."},template:"흥미로운 발표였습니다. 다만 그 결론은 {0} {1}, 표본의 {2} 점은 어떻게 보십니까?",blanks:[[{ko:"선행 연구와",en:"with the prior research",zh:"与先行研究",vi:"với nghiên cứu trước đây",note:"Academic; frames the objection against established work.",noteZh:"学术用语；将异议置于既有研究的对照之下。",noteVi:"Học thuật; đặt sự phản biện trong tương quan với các công trình đã có."},{ko:"기존 통념과",en:"with conventional wisdom",zh:"与既有的普遍看法",vi:"với quan niệm thông thường",note:"Positions the claim against the received view.",noteZh:"将该主张与公认的观点相对照。",noteVi:"Đặt lập luận đối lập với quan điểm đã được công nhận."}],[{ko:"상충하는 듯한데",en:"seems to be at odds, and",zh:"似乎相互抵触，",vi:"có vẻ mâu thuẫn, và",note:"상충하다 = to conflict; softened with -는 듯 for politeness.",noteZh:"상충하다＝冲突；用 -는 듯 加以委婉缓和。",noteVi:"상충하다 = xung đột; được làm dịu bằng -는 듯 để lịch sự hơn."},{ko:"배치되는 면이 있는데",en:"runs counter in some respects, and",zh:"在某些方面有所相悖，",vi:"có phần trái ngược ở một số điểm, và",note:"배치되다 = to be contrary; measured, formal hedge.",noteZh:"배치되다＝相悖；分寸得当、正式的委婉说法。",noteVi:"배치되다 = trái ngược; cách nói thận trọng, trang trọng và có chừng mực."}],[{ko:"대표성이 부족하다는",en:"lacking representativeness",zh:"缺乏代表性这一",vi:"thiếu tính đại diện",note:"Standard methodological critique of a sample.",noteZh:"对样本在方法论上的标准批评。",noteVi:"Lời phê bình phương pháp luận tiêu chuẩn đối với mẫu nghiên cứu."},{ko:"편향이 우려된다는",en:"raising concern of bias",zh:"令人担忧存在偏差这一",vi:"gây lo ngại về sự thiên lệch",note:"Points to potential sampling bias diplomatically.",noteZh:"委婉地指出可能存在的抽样偏差。",noteVi:"Khéo léo chỉ ra khả năng có sai lệch trong lấy mẫu."}]],example:{ko:"흥미로운 발표였습니다. 다만 그 결론은 선행 연구와 상충하는 듯한데, 표본의 대표성이 부족하다는 점은 어떻게 보십니까?",en:"It was an interesting talk. That said, the conclusion seems at odds with prior research — how do you view the point that the sample lacks representativeness?",zh:"这是一场很有意思的报告。不过，那个结论似乎与先行研究相互抵触，对于样本缺乏代表性这一点，您怎么看？",vi:"Đây là một bài thuyết trình thú vị. Tuy nhiên, kết luận đó dường như mâu thuẫn với nghiên cứu trước đây — ngài nghĩ sao về việc mẫu nghiên cứu thiếu tính đại diện?"},alternatives:[{ko:"반론의 여지가 있어 보입니다만, 보완 설명을 부탁드려도 될까요?",en:"There seems to be room for counterargument; may I ask for further clarification?",zh:"看来还有可商榷之处，能否请您做些补充说明？",vi:"Có vẻ như vẫn còn chỗ để phản biện; tôi có thể xin ngài giải thích thêm được không?",note:"Very diplomatic academic pushback.",noteZh:"非常委婉的学术反驳。",noteVi:"Cách phản biện học thuật rất khéo léo, nhã nhặn."},{ko:"인과 관계로 단정하기엔 다소 성급하지 않나 싶습니다.",en:"I wonder if it's a little hasty to assert a causal relationship.",zh:"要断定为因果关系，恐怕还稍显草率。",vi:"Tôi tự hỏi liệu việc khẳng định mối quan hệ nhân quả như vậy có hơi vội vàng không.",note:"Cautions against overclaiming causation.",noteZh:"提醒不要过度断言因果关系。",noteVi:"Cảnh báo về việc khẳng định quá mức mối quan hệ nhân quả."}]},{id:"ko-dlg-c2-formal-001",level:"C2",situation:"formal",context:{ko:"공식 행사에서 축사를 시작할 때",en:"Opening a congratulatory address at a formal event",zh:"在正式活动上开始致贺辞时",vi:"Khi bắt đầu bài phát biểu chúc mừng tại một sự kiện trang trọng"},prompt:{ko:"이어서 축사가 있겠습니다. 한 말씀 부탁드립니다.",en:"Next we have the congratulatory address. Please say a few words.",zh:"接下来是贺辞环节，有请您讲几句。",vi:"Tiếp theo sẽ là phần phát biểu chúc mừng. Kính mời ngài nói đôi lời."},template:"이 자리를 빌려, 행사를 준비하신 모든 분께 {0}. 아울러 {1} 진심으로 {2}.",blanks:[[{ko:"심심한 감사를 드립니다",en:"I extend my heartfelt gratitude",zh:"致以深切的谢意",vi:"xin gửi lời cảm ơn sâu sắc",note:"심심한 = deep/profound (深甚), a formal fixed phrase.",noteZh:"심심한＝深切／深厚（深甚），正式的固定短语。",noteVi:"심심한 = sâu sắc/thâm sâu (深甚), một cụm từ cố định trang trọng."},{ko:"깊은 감사의 말씀을 전합니다",en:"I convey my deep thanks",zh:"转达深深的谢意",vi:"xin gửi lời cảm ơn chân thành",note:"Slightly plainer but still ceremonial.",noteZh:"略为朴实，但仍显庄重。",noteVi:"Hơi giản dị hơn nhưng vẫn trang trọng."}],[{ko:"여러분의 무궁한 발전을",en:"your everlasting prosperity",zh:"各位的前程无量",vi:"sự phát triển thịnh vượng mãi mãi của quý vị",note:"Boilerplate well-wish for the audience.",noteZh:"对听众的套语式祝福。",noteVi:"Lời chúc mẫu dành cho khán giả."},{ko:"이 자리에 함께한 인연을",en:"the bond of being here together",zh:"今日相聚于此的缘分",vi:"duyên phận được cùng nhau có mặt tại đây",note:"Warmer, more personal register.",noteZh:"更温暖、更具个人色彩的语体。",noteVi:"Văn phong ấm áp và mang tính cá nhân hơn."}],[{ko:"기원합니다",en:"I wish for",zh:"祝愿",vi:"xin cầu chúc",note:"기원하다 = to wish/pray for; elevated over 바라다.",noteZh:"기원하다＝祝愿／祈愿；比 바라다 更文雅。",noteVi:"기원하다 = cầu chúc/cầu nguyện; trang nhã hơn 바라다."},{ko:"축원합니다",en:"I offer my blessing",zh:"祝福",vi:"xin gửi lời chúc phúc",note:"축원하다 = to wish blessings; ceremonial.",noteZh:"축원하다＝祝福；庄重用语。",noteVi:"축원하다 = cầu phúc; cách nói trang trọng."}]],example:{ko:"이 자리를 빌려, 행사를 준비하신 모든 분께 심심한 감사를 드립니다. 아울러 여러분의 무궁한 발전을 진심으로 기원합니다.",en:"Taking this opportunity, I extend my heartfelt gratitude to all who prepared this event. I also sincerely wish you everlasting prosperity.",zh:"借此机会，谨向筹办本次活动的所有人士致以深切的谢意。同时，衷心祝愿各位前程无量。",vi:"Nhân dịp này, tôi xin gửi lời cảm ơn sâu sắc đến tất cả những người đã chuẩn bị cho sự kiện này. Đồng thời, tôi chân thành cầu chúc quý vị phát triển thịnh vượng mãi mãi."},alternatives:[{ko:"변변치 못한 축사이오나, 너른 마음으로 들어 주시기 바랍니다.",en:"It is but a humble address; I ask that you receive it generously.",zh:"这只是一篇不成敬意的贺辞，还望各位宽宏雅纳。",vi:"Đây chỉ là một bài phát biểu khiêm tốn, mong quý vị rộng lòng đón nhận.",note:"Humble self-lowering opener common in speeches.",noteZh:"演讲中常见的自谦式开场白。",noteVi:"Lời mở đầu khiêm nhường, tự hạ thấp bản thân, thường gặp trong các bài phát biểu."},{ko:"이것으로 축사를 갈음하고자 합니다.",en:"With this, I would like to conclude my address.",zh:"谨以此代替贺辞，就此作结。",vi:"Xin phép được khép lại bài phát biểu chúc mừng bằng những lời này.",note:"Set phrase to close a formal speech.",noteZh:"收束正式演讲的固定用语。",noteVi:"Cụm từ cố định để kết thúc một bài phát biểu trang trọng."}]},{id:"ko-dlg-c2-idioms-001",level:"C2",situation:"idioms",context:{ko:"어려움을 겪은 동료를 격려할 때",en:"Encouraging a colleague who has been through hardship",zh:"鼓励经历了困境的同事时",vi:"Khi động viên một đồng nghiệp đã trải qua khó khăn"},prompt:{ko:"프로젝트가 엎어져서 그동안 고생한 게 다 물거품이 됐어요.",en:"The project fell through, so all the effort came to nothing.",zh:"项目泡汤了，这段时间的辛苦全都白费了。",vi:"Dự án đã đổ bể nên bao công sức bỏ ra suốt thời gian qua đều tan thành mây khói."},template:"너무 자책하지 마세요. {0} 하잖아요. 이번 일이 {1} 분명 {2} 거예요.",blanks:[[{ko:"원숭이도 나무에서 떨어진다고",en:"even monkeys fall from trees",zh:"都说猴子也会从树上掉下来",vi:"người ta vẫn nói khỉ cũng có lúc rơi khỏi cây",note:"Native proverb: anyone, even the skilled, can stumble.",noteZh:"本土谚语：任何人，哪怕是能手，也会失手。",noteVi:"Tục ngữ thuần Hàn: bất kỳ ai, kể cả người giỏi, cũng có lúc vấp ngã."},{ko:"비 온 뒤에 땅이 굳는다고",en:"the ground hardens after the rain",zh:"都说雨过之后地更实",vi:"người ta vẫn nói sau cơn mưa đất sẽ cứng lại",note:"Proverb: hardship leaves you stronger.",noteZh:"谚语：经历磨难反而让人更坚强。",noteVi:"Tục ngữ: trải qua gian khổ sẽ khiến con người vững vàng hơn."}],[{ko:"전화위복이 되어",en:"turning into a blessing in disguise",zh:"因祸得福",vi:"biến thành cái may trong cái rủi",note:"전화위복 = misfortune turned to fortune.",noteZh:"전화위복＝转祸为福。",noteVi:"전화위복 = họa biến thành phúc."},{ko:"좋은 약이 되어",en:"turning out to be a valuable lesson (lit. good medicine)",zh:"成为一剂良药",vi:"trở thành liều thuốc quý",note:"A bitter experience that ultimately helps you grow.",noteZh:"苦涩的经历最终助你成长。",noteVi:"Một trải nghiệm cay đắng nhưng cuối cùng lại giúp ta trưởng thành."}],[{ko:"좋은 밑거름이 될",en:"become good fertile soil (a foundation)",zh:"会成为很好的养分（根基）",vi:"sẽ trở thành nền tảng bồi đắp tốt",note:"밑거름 = nourishing base for future growth.",noteZh:"밑거름＝滋养未来成长的基础。",noteVi:"밑거름 = nền tảng nuôi dưỡng cho sự phát triển sau này."},{ko:"값진 교훈으로 남을",en:"remain as a valuable lesson",zh:"会作为宝贵的教训留下",vi:"sẽ đọng lại như một bài học quý giá",note:"Reframes the setback as worthwhile experience.",noteZh:"把挫折重新诠释为值得的经历。",noteVi:"Diễn giải lại thất bại như một trải nghiệm đáng giá."}]],example:{ko:"너무 자책하지 마세요. 원숭이도 나무에서 떨어진다고 하잖아요. 이번 일이 전화위복이 되어 분명 좋은 밑거름이 될 거예요.",en:"Don't blame yourself too much. Even monkeys fall from trees, you know. This setback may turn into a blessing and surely become good foundation.",zh:"别太自责了。都说猴子也会从树上掉下来嘛。这件事说不定因祸得福，一定会成为很好的养分的。",vi:"Đừng tự trách mình quá vậy. Người ta vẫn nói khỉ cũng có lúc rơi khỏi cây mà. Việc lần này biết đâu lại là cái may trong cái rủi, chắc chắn sẽ trở thành nền tảng tốt."},alternatives:[{ko:"실패는 성공의 어머니라잖아요.",en:"Failure is the mother of success, as they say.",zh:"常言道，失败乃成功之母嘛。",vi:"Người ta vẫn nói thất bại là mẹ thành công mà.",note:"Classic consolation proverb.",noteZh:"经典的安慰谚语。",noteVi:"Câu tục ngữ an ủi kinh điển."},{ko:"이 또한 지나가리라 생각하세요.",en:"Tell yourself that this too shall pass.",zh:"就这样想吧——这一切也终将过去。",vi:"Hãy nghĩ rằng rồi điều này cũng sẽ qua thôi.",note:"Reflective, somewhat literary comfort.",noteZh:"带有沉思意味、略显文雅的安慰。",noteVi:"Lời an ủi mang tính suy tư, có phần văn chương."}]},{id:"ko-dlg-c2-nuance-001",level:"C2",situation:"nuance",context:{ko:"예상과 다른 결과에 대해 의견을 말할 때",en:"Commenting on a result that defied expectations",zh:"对出乎意料的结果发表看法时",vi:"Khi nêu ý kiến về một kết quả trái với dự đoán"},prompt:{ko:"할인 행사를 했는데 매출이 오히려 줄었어요. 이해가 안 되네요.",en:"We ran a discount, but sales actually dropped. I can't make sense of it.",zh:"搞了打折促销，销售额反而下降了。真让人想不通。",vi:"Đã tổ chức chương trình giảm giá nhưng doanh số lại giảm. Thật không thể hiểu nổi."},template:"{0} 가격을 낮추면 {1} 브랜드 가치가 떨어져 보일 수 있어요. {2} 정공법이 나았을지도 모르죠.",blanks:[[{ko:"역설적이게도",en:"paradoxically",zh:"看似矛盾的是",vi:"trớ trêu thay",note:"Frames the counterintuitive outcome elegantly.",noteZh:"优雅地引出这一反直觉的结果。",noteVi:"Cách dẫn dắt tinh tế cho kết quả trái với trực giác này."},{ko:"오히려",en:"on the contrary",zh:"反而",vi:"trái lại",note:"Flags a result opposite to expectation.",noteZh:"标示出与预期相反的结果。",noteVi:"Đánh dấu kết quả trái ngược với dự đoán."}],[{ko:"되레",en:"rather / instead",zh:"反倒",vi:"trái lại / thay vào đó",note:"되레 = colloquial contraction of 도리어; emphatic reversal.",noteZh:"되레＝도리어 的口语缩略；强调反转。",noteVi:"되레 = dạng rút gọn khẩu ngữ của 도리어; nhấn mạnh sự đảo ngược."},{ko:"자칫",en:"all too easily / at the slightest",zh:"一不小心（就）",vi:"chỉ cần sơ suất một chút (là)",note:"자칫 = warns of an easy slip into a bad outcome.",noteZh:"자칫＝提醒稍有不慎便会滑向坏结果。",noteVi:"자칫 = cảnh báo rằng chỉ cần bất cẩn một chút là sẽ dẫn đến kết quả xấu."}],[{ko:"차라리",en:"if anything / rather",zh:"倒不如",vi:"thà rằng",note:"Picks the better of imperfect options.",noteZh:"在都不理想的选项中挑较好的那个。",noteVi:"Chọn phương án tốt hơn trong số các lựa chọn không hoàn hảo."},{ko:"어쩌면",en:"perhaps",zh:"或许",vi:"có lẽ",note:"Tentative; leaves room for doubt.",noteZh:"语气试探，留有余地。",noteVi:"Mang tính dò xét, để ngỏ khả năng nghi ngờ."}]],example:{ko:"역설적이게도 가격을 낮추면 되레 브랜드 가치가 떨어져 보일 수 있어요. 차라리 정공법이 나았을지도 모르죠.",en:"Paradoxically, cutting the price can actually make the brand look cheaper. A straightforward approach might have been better.",zh:"看似矛盾的是，降价反倒可能让品牌显得掉价。倒不如用正规打法或许更好。",vi:"Trớ trêu thay, hạ giá có thể trái lại khiến thương hiệu trông rẻ tiền hơn. Thà rằng dùng cách làm chính đạo có khi lại tốt hơn."},alternatives:[{ko:"겉보기와 달리 소비자 심리는 단순하지 않더라고요.",en:"Contrary to appearances, consumer psychology isn't simple.",zh:"与表面看到的不同，消费者心理其实并不简单。",vi:"Khác với vẻ bề ngoài, tâm lý người tiêu dùng không hề đơn giản.",note:"겉보기와 달리 = contrary to how it looks.",noteZh:"겉보기와 달리＝与表面所见相反。",noteVi:"겉보기와 달리 = trái với vẻ bề ngoài."},{ko:"두말할 나위 없이 데이터를 더 들여다봐야겠어요.",en:"Needless to say, we need to dig into the data more.",zh:"不言而喻，我们得再深入分析一下数据。",vi:"Không cần phải nói, chúng ta cần xem xét kỹ hơn dữ liệu.",note:"두말할 나위 없이 = it goes without saying.",noteZh:"두말할 나위 없이＝不言而喻。",noteVi:"두말할 나위 없이 = không cần phải nói / hiển nhiên."}]},{id:"ko-dlg-c2-formal-002",level:"C2",situation:"formal",context:{ko:"공식 사과문을 발표할 때",en:"Issuing an official statement of apology",zh:"发表正式道歉声明时",vi:"Khi đưa ra tuyên bố xin lỗi chính thức"},prompt:{ko:"이번 사태에 대한 회사의 입장을 밝혀 주시기 바랍니다.",en:"Please clarify the company's position on this matter.",zh:"请贵公司就此次事件表明立场。",vi:"Kính mong quý công ty làm rõ lập trường về sự việc lần này."},template:"먼저, 심려를 끼쳐 드린 점 {0}. 저희는 이번 일을 {1}, 재발 방지를 위해 {2}.",blanks:[[{ko:"머리 숙여 사과드립니다",en:"we apologize with our heads bowed",zh:"俯首致歉／低头谢罪",vi:"chúng tôi cúi đầu xin lỗi",note:"머리 숙여 = bowing the head; the standard contrite formula.",noteZh:"머리 숙여＝低头俯首；标准的谢罪套语。",noteVi:"머리 숙여 = cúi đầu; công thức tạ lỗi tiêu chuẩn."},{ko:"깊이 사죄드립니다",en:"we deeply apologize",zh:"深深谢罪",vi:"chúng tôi thành thật tạ lỗi sâu sắc",note:"사죄 = atonement; graver than 사과.",noteZh:"사죄＝谢罪／赎罪；比 사과 更为郑重。",noteVi:"사죄 = tạ tội/chuộc lỗi; nghiêm trọng hơn 사과."}],[{ko:"엄중히 받아들이며",en:"taking it with the utmost seriousness, and",zh:"严肃对待，",vi:"nghiêm túc tiếp nhận, và",note:"엄중히 = gravely/sternly; signals accountability.",noteZh:"엄중히＝严正／郑重地；表明担责态度。",noteVi:"엄중히 = nghiêm trọng/nghiêm khắc; thể hiện thái độ chịu trách nhiệm."},{ko:"뼈아프게 새기며",en:"engraving it painfully (as a lesson), and",zh:"刻骨铭心地引以为戒，",vi:"khắc cốt ghi tâm một cách đau đớn, và",note:"뼈아프게 = to the bone; vivid, contrite.",noteZh:"뼈아프게＝痛入骨髓；形象而深切的自省。",noteVi:"뼈아프게 = thấu xương; hình ảnh sinh động, thể hiện sự ăn năn sâu sắc."}],[{ko:"만전을 기하겠습니다",en:"we will take every possible measure",zh:"将采取万全之策",vi:"chúng tôi sẽ làm mọi biện pháp có thể",note:"만전을 기하다 = to leave nothing to chance; formal pledge.",noteZh:"만전을 기하다＝万无一失、不留隐患；正式承诺。",noteVi:"만전을 기하다 = không để sót bất kỳ rủi ro nào; lời cam kết trang trọng."},{ko:"최선을 다하겠습니다",en:"we will do our utmost",zh:"将竭尽全力",vi:"chúng tôi sẽ nỗ lực hết sức",note:"Plainer but acceptable closing commitment.",noteZh:"较朴实但同样得体的收尾承诺。",noteVi:"Lời cam kết kết thúc giản dị nhưng vẫn phù hợp."}]],example:{ko:"먼저, 심려를 끼쳐 드린 점 머리 숙여 사과드립니다. 저희는 이번 일을 엄중히 받아들이며, 재발 방지를 위해 만전을 기하겠습니다.",en:"First, we bow our heads in apology for the worry we have caused. We take this matter with the utmost seriousness and will spare no effort to prevent any recurrence.",zh:"首先，就给各位带来忧扰一事，我们俯首致歉。我们将严肃对待此次事件，并为防止再次发生采取万全之策。",vi:"Trước hết, chúng tôi xin cúi đầu xin lỗi vì đã gây ra sự lo lắng cho quý vị. Chúng tôi sẽ nghiêm túc tiếp nhận sự việc lần này và làm mọi biện pháp có thể để phòng ngừa tái diễn."},alternatives:[{ko:"변명의 여지가 없음을 통감하고 있습니다.",en:"We keenly feel that there is no room for excuse.",zh:"我们深切地意识到此事毫无辩解余地。",vi:"Chúng tôi thấm thía nhận ra rằng không có chỗ để biện minh.",note:"통감하다 = to feel acutely; heavy, formal contrition.",noteZh:"통감하다＝深切体会；沉重而正式的悔过。",noteVi:"통감하다 = cảm nhận sâu sắc; sự hối lỗi nặng nề, trang trọng."},{ko:"국민 여러분께 너른 양해를 부탁드립니다.",en:"We ask the public for their generous understanding.",zh:"恳请全体国民宽宏谅解。",vi:"Kính mong toàn thể quốc dân lượng thứ.",note:"Standard public-apology closing request.",noteZh:"公开道歉时收尾的标准请求用语。",noteVi:"Lời thỉnh cầu kết thúc tiêu chuẩn trong lời xin lỗi công khai."}]}]],683565)}]);